INSERT INTO `seances_pedagogiques` (`id`, `sequence_id`, `annee_scolaire_id`, `date_seance`, `objectif_pedagogique`, `description_activites`, `observations_formateur`, `dispositions_prochaine`, `heures_realisees`, `heures_officielles`, `heures_reelles`, `controle_continu`) VALUES
(6, 195, 1, '2024-10-01 08:00:00', 'Identifier clairement l’intérêt de la mise en place d’un système de comptabilité analytique au sein de l’entreprise', 'Introduction aux concepts de la comptabilité analytique et ses bénéfices pour la gestion d’entreprise.', 'Bonne compréhension générale, questions sur les bénéfices spécifiques.', 'Prévoir des études de cas sur l\'impact réel de la comptabilité analytique.', NULL, 4, 3.00, 0),
(7, 195, 1, '2024-10-08 08:00:00', 'Identifier le processus de production de l’entreprise et les objectifs de gestion recherchés par les responsables', 'Analyse des étapes du processus de production et des objectifs des responsables financiers.', 'Participation active, mais manque de familiarité avec les termes techniques.', 'Introduire un glossaire des termes clés.', NULL, 4, 3.00, 0),
(8, 195, 1, '2024-10-15 08:00:00', 'Identifier nommément les centres d’analyse de l’entreprise', 'Identification des centres et leur rôle dans l’entreprise.', 'Bonne identification, difficultés dans certains exemples complexes.', 'Fournir des schémas explicatifs des centres d’analyse.', NULL, 4, 3.00, 0),
(9, 195, 1, '2024-10-22 08:00:00', 'Organiser les flux d’informations entre les différents centres d’analyse pour les besoins de la comptabilité analytique', 'Démonstration des flux d’informations entre les centres pour optimiser la gestion.', 'Maîtrise limitée des flux d’informations.', 'Simuler un flux d’informations avec un exemple simplifié.', NULL, 4, 3.00, 0),
(10, 195, 1, '2024-10-29 08:00:00', 'Identifier clairement les charges incorporables', 'Introduction aux charges incorporables : définition, classification, et exemples pratiques. Explication des charges à inclure dans le calcul des coûts analytiques.', 'Les stagiaires ont bien compris la définition, mais confondent parfois avec les charges non incorporables.', 'Prévoir des exercices de distinction entre charges incorporables et non incorporables avec des cas pratiques.', NULL, 4, 3.00, 0),
(11, 196, 1, '2024-11-05 08:00:00', 'Distinguer nettement entre charges directes et charges indirectes', 'Explication des charges directes et indirectes avec exemples pratiques.', 'Bon engagement, besoin de précisions sur la répartition des charges.', 'Prévoir des exercices de répartition détaillés.', NULL, 4, 3.00, 0),
(12, 196, 1, '2024-11-12 08:00:00', 'Déterminer les charges indirectes et leurs clés de répartition entre centres d’analyse', 'Utilisation de clés de répartition pour affecter les charges indirectes aux centres d’analyse.', 'Bonne compréhension globale, erreurs dans l’application des clés.', 'Revoir les étapes de calcul des clés de répartition.', NULL, 4, 3.00, 0),
(13, 196, 1, '2024-11-19 08:00:00', 'Tenir les comptes de stocks de manière permanente', 'Gestion des stocks permanents avec méthode FIFO ou LIFO.', 'Compréhension partielle des méthodes de gestion.', 'Proposer des exercices spécifiques sur la méthode FIFO.', NULL, 4, 3.00, 0),
(14, 197, 1, '2024-11-26 08:00:00', 'Déterminer les coûts d’achat des matières premières ou des marchandises', 'Calcul des coûts d’achat des matières premières .', 'Difficultés dans les calculs complexes.', 'Donner des exercices pratiques avec des solutions détaillées.', NULL, 4, 3.00, 0),
