(76, 329, 1, '2024-11-14 14:00:00', 'Définir les dispositions légales relatives aux instruments juridiques de commerce', 'Présentation des règles légales et des obligations associées aux instruments juridiques tels que les lettres de change, les chèques et les effets de commerce.', 'Les étudiants montrent des difficultés à distinguer les spécificités des différents instruments juridiques.', 'Prévoir des exemples concrets pour illustrer chaque instrument. Introduire des études de cas et des scénarios pratiques.', NULL, 2, 2.00, 0),
(77, 330, 1, '2024-11-21 14:00:00', 'Appliquer les droits communs des contrats commerciaux', 'Expliquer et mettre en pratique les règles générales applicables à tous les contrats commerciaux (formalisme, consentement, etc.).', 'Les cas pratiques ne sont pas toujours bien maîtrisés par les étudiants.', 'Organiser des simulations de rédaction et de négociation de contrats.', NULL, 2, 2.00, 0),
(78, 330, 1, '2024-11-28 14:00:00', 'Respecter des principes généraux de rédaction de contrats commerciaux', 'Détailler les étapes et principes essentiels pour la rédaction de contrats commerciaux précis et juridiquement valides.', 'Les termes juridiques sont parfois mal utilisés.', 'Prévoir des exercices de rédaction et révision de contrats pour chaque groupe d\'apprenants.', NULL, 2, 2.00, 0),
(79, 330, 1, '2024-12-05 14:00:00', 'Traiter les transactions commerciales dans un contexte contractuel', 'Identifier les normes légales applicables à l’émission et la vérification des chèques, ainsi que les sanctions encourues en cas de non-respect.', 'Les aspects légaux des chèques sont souvent mal compris.', 'Introduire des cas pratiques sur la vérification de chèques et la gestion des litiges associés.', NULL, 2, 2.00, 0),
(80, 331, 1, '2024-12-19 14:00:00', 'Définir les différents moyens de paiement pratiqués par l’entreprise', 'Expliquer les procédures légales et recours possibles en cas de litige lié à un chèque ou un effet de commerce.', 'Les étapes de gestion des contentieux sont parfois mal assimilées', 'Simuler des contentieux où les étudiants doivent rédiger les documents nécessaires pour les démarches légales.', NULL, 2, 2.00, 0),
(81, 331, 1, '2024-12-26 14:00:00', 'Remplir judicieusement une lettre de change', 'Présentation des éléments obligatoires d’une lettre de change et démonstration de la manière de la remplir correctement.', 'Les étudiants confondent parfois les parties obligatoires et facultatives.', 'Ajouter des exemples remplis et des exercices pratiques pour vérifier leur compréhension.', NULL, 2, 2.00, 0),
(82, 331, 1, '2025-01-02 14:00:00', 'Respecter à la lettre les règles de paiements en espèces', 'Explication des obligations légales et des limites de paiements en espèces dans le cadre commercial.', 'Les étudiants montrent une compréhension limitée des plafonds réglementaires pour les paiements en espèces.', 'Introduire des cas pratiques pour simuler des paiements en espèces dans différents contextes légaux.', NULL, 2, 2.00, 0),
(83, 331, 1, '2025-01-09 14:00:00', 'Traiter et vérifier les chèques sous ses aspects réglementaires', 'Étude des règles de rédaction, vérification et validité des chèques dans le cadre commercial.', 'Difficultés rencontrées pour repérer les erreurs dans des chèques simulés.', 'Prévoir des exercices avec des exemples de chèques incorrects à corriger.', NULL, 2, 2.00, 0),
(84, 331, 1, '2025-01-16 14:00:00', 'Définir les règles de contentieux des chèques et effets de commerce', 'Analyse des procédures légales en cas de litiges liés aux chèques et autres effets de commerce.', 'Les étudiants peinent à comprendre les étapes du contentieux et les recours possibles.', 'Fin de l\'unité de formation', NULL, 2, 2.00, 0),
(85, 236, 1, '2024-10-04 08:00:00', 'Saisir efficacement les données', 'Formation à la saisie rapide et précise des données comptables et administratives dans un tableur ou logiciel de gestion.', 'Les étudiants manquent parfois de rigueur dans la saisie des chiffres et données comptables.', 'Introduire des exercices pratiques avec des données comptables à compléter pour améliorer la précision', NULL, 4, 3.00, 0),
(86, 236, 1, '2024-10-11 08:00:00', 'Trier les données selon les critères les plus pertinents', 'Tri des données comptables et administratives selon les catégories (clients, fournisseurs, produits, etc.) dans un logiciel de gestion.', 'Les critères multiples de tri ne sont pas toujours bien compris.', 'Fournir des cas pratiques de tri par catégories pertinentes dans un contexte de gestion d’entreprise', NULL, 4, 3.00, 0),
(87, 236, 1, '2024-10-18 08:00:00', 'Classer les données en fonction des objectifs de l’enquête', 'Organisation des données pour établir des tableaux de bord ou des rapports d’analyse financière et de performance.', 'Les étudiants peinent à relier les objectifs à la structure des données.', 'Proposer des études de cas pour l’organisation des données selon des objectifs précis.', NULL, 4, 3.00, 0),
(88, 236, 1, '2024-10-25 08:00:00', 'Croiser les données en faisant ressortir les liens de corrélations les plus significatifs', 'Utilisation de tableaux croisés dynamiques pour analyser la relation entre les ventes, les dépenses et les performances globales.', 'Les étudiants rencontrent des difficultés à interpréter les corrélations entre variables financières.', 'Fournir des scénarios concrets liés à l’analyse des performances d’une entreprise.', NULL, 4, 3.00, 0),
(89, 236, 1, '2024-11-01 08:00:00', 'Editer et présenter les résultats de façon claire', 'Conception de rapports professionnels avec tableaux et graphiques pour résumer les performances financières et opérationnelles.', 'Les graphiques utilisés ne sont pas toujours clairs ou pertinents.', 'Inclure des exemples de rapports d’entreprise et des exercices de correction pour les améliorer.', NULL, 4, 3.00, 0),
(90, 237, 1, '2024-11-08 08:00:00', 'Identifier les éléments constitutifs de la base de données de l’entreprise', 'Définition des entités clés comme les clients, fournisseurs, produits, et services pour créer une base de données adaptée aux besoins de gestion.', 'Les concepts de base ne sont pas bien assimilés par tous les étudiants.', 'Prévoir une session dédiée à l’identification des besoins des bases de données dans un contexte de gestion.', NULL, 4, 3.00, 0),
(91, 237, 1, '2024-11-15 08:00:00', 'Créer les tables adaptées à la base de données identifiée', 'Mise en place des tables pour stocker les informations nécessaires comme les factures, paiements, et commandes dans un logiciel de gestion.', 'La structure des tables est parfois incohérente.', 'Proposer des exercices de création de tables dans un logiciel comme Microsoft Access ou Excel.', NULL, 4, 3.00, 0),
(92, 237, 1, '2024-11-22 08:00:00', 'Formuler les requêtes', 'Formation à l’écriture de requêtes SQL simples pour extraire des informations spécifiques comme les soldes clients ou les transactions non réglées.', 'Les requêtes complexes restent difficiles à maîtriser.', 'Fournir des exercices pratiques basés sur des scénarios financiers simples.', NULL, 4, 3.00, 0),
(93, 237, 1, '2024-11-29 08:00:00', 'Créer les formulaires répondants aux besoins de l’entreprise en information', 'Conception de formulaires pour la saisie des données clients, factures ou inventaires dans des outils adaptés comme Access.', 'Les formulaires manquent parfois d’ergonomie.', 'Continuer sur le même objectif pédagogique', NULL, 4, 3.00, 0),
(94, 237, 1, '2024-12-06 08:00:00', 'Créer les formulaires répondants aux besoins de l’entreprise en information', '-Suite de l\'objectif pédagogique\r\n-Projection', 'Objectif atteint totalement', 'Proposer des études de cas pour concevoir des formulaires intuitifs.', NULL, 4, 3.00, 0),
(95, 237, 1, '2024-12-20 08:00:00', 'Créer les états adaptés à la nature des informations recherchées', 'Génération de rapports périodiques pour suivre les indicateurs clés comme les ventes, les dépenses et la trésorerie.', 'Les rapports générés ne sont pas toujours adaptés aux besoins des gestionnaires.', 'Fournir des modèles de rapports d’entreprise à adapter et personnaliser.', NULL, 4, 3.00, 0),
(96, 237, 1, '2024-12-27 08:00:00', 'Créer les états adaptés à la nature des informations recherchées', '-Continuer sur le même objectif pédagogique\r\n-Presentation sur vidéo projecteur', 'Bonne maîtrise de l\'objectif', 'Commencer un nouveau objectif pédagogique', NULL, 4, 3.00, 0),
(97, 237, 1, '2025-01-03 08:00:00', 'Gérer les liens hypertexte pour se connecter aux sites externes', 'Intégration et gestion de liens hypertexte vers des ressources en ligne comme les plateformes bancaires ou les portails clients.', 'Les liens ne sont pas toujours bien configurés dans les documents.', 'Proposer des exercices pratiques de création et de test des hyperliens.', NULL, 4, 3.00, 0),
(98, 237, 1, '2025-01-10 08:00:00', 'Gérer les liens hypertexte pour se connecter aux sites externes', '-Suite de l\'objectif pédogogique\r\n-Exercices pratiques de création et de test des hyperliens', 'Séance riche de question et de participation', 'Entamer l\'objectif pédagogique suivant', NULL, 4, 3.00, 0),
(99, 164, 1, '2024-10-03 14:00:00', 'Nommer précisément toutes les fonctions et structures internes de l’entreprise', 'Identification et classification des principales fonctions de l’entreprise (administration, finance, production, marketing, etc.).', 'Certains étudiants confondent les fonctions principales avec des tâches spécifiques.', 'Prévoir des exemples d’organigrammes réels pour illustrer les fonctions de l’entreprise.', NULL, 4, 3.00, 0),
(100, 164, 1, '2024-10-10 14:00:00', 'Repérer au moins tous les liens formels entre les différentes fonctions et structures de l’entreprise', 'Analyse des interactions et des dépendances entre les services (collaboration entre marketing et production, etc.).', 'Difficultés à visualiser les liens entre services dans une organisation complexe', 'Fournir des études de cas d’organisations avec des exemples concrets de relations inter-services', NULL, 4, 3.00, 0),
(101, 164, 1, '2024-10-17 14:00:00', 'Spécifier les tâches et missions attribuées à chacune des fonctions de l’entreprise', 'Définir le rôle et les responsabilités de chaque fonction pour atteindre les objectifs de l’entreprise.', 'La distinction entre mission stratégique et opérationnelle n’est pas toujours claire.', 'Proposer des exercices pratiques de rédaction de fiches de poste.', NULL, 4, 3.00, 0),
(102, 164, 1, '2024-10-24 14:00:00', 'Présenter de manière exhaustive les moyens et modes de communication interne de l’entreprise', 'Étude des outils de communication (réunions, emails, plateformes collaboratives) et leur impact sur la performance.', 'Les étudiants manquent d’exemples concrets d’outils modernes de communication.', 'Organiser une simulation d’utilisation d’outils comme Slack ou Microsoft Teams.', NULL, 4, 3.00, 0),
(103, 165, 1, '2024-10-31 14:00:00', 'Expliquer clairement la notion de profit maximum', 'Définition et calcul du profit en fonction des recettes et des coûts, avec des exemples d’optimisation', 'Les concepts mathématiques derrière le profit sont parfois mal maîtrisés.', 'Introduire des exercices progressifs de calcul et d’analyse du profit.', NULL, 4, 3.00, 0),
(104, 165, 1, '2024-11-07 14:00:00', 'Expliciter tous les éléments qui concourent à atteindre la qualité totale', 'Introduction au concept de qualité totale, outils et indicateurs de mesure de la qualité dans l’entreprise.', 'Peu de familiarité avec les méthodologies de gestion de la qualité.', 'Prévoir une étude de cas illustrant l’impact de la qualité sur la performance globale.', NULL, 4, 3.00, 0),
(105, 165, 1, '2024-11-14 14:00:00', 'Repérer tous les moyens adoptés par l’entreprise pour valoriser ses ressources humaines', 'Analyse des politiques RH (formation, motivation, plan de carrière) et leur rôle dans la performance de l’entreprise.', 'Les étudiants négligent souvent l’impact de la formation continue.', 'Proposer un projet de simulation d’élaboration d’un plan de formation pour une entreprise fictive.', NULL, 4, 3.00, 0),
(106, 166, 1, '2024-11-21 14:00:00', 'Identifier tous les partenaires externes par marché ciblé', 'Étude des partenaires commerciaux, financiers et institutionnels en fonction des segments de marché', 'La distinction entre partenaires stratégiques et opérationnels reste floue.', 'Fournir une typologie des partenaires avec des exemples concrets', NULL, 4, 3.00, 0),
(107, 166, 1, '2024-11-28 14:00:00', 'Caractériser de manière précise la demande sur les marchés ciblés par l’entreprise', 'Analyse des besoins clients, segmentation et positionnement des produits/services pour répondre à la demande.', 'Les outils comme le SWOT ou les études de marché ne sont pas toujours bien utilisés', 'Fournir des exemples concrets d’analyse de marché pour une entreprise locale', NULL, 4, 3.00, 0),
(108, 166, 1, '2024-12-05 14:00:00', 'Définir les lois concurrentielles dans les marchés de l’entreprise', 'Étude des différentes formes de concurrence (monopole, oligopole, concurrence parfaite) et leur impact sur l’entreprise.', 'Difficultés à comprendre les implications juridiques des lois concurrentielles.', 'Prévoir une simulation de situation concurrentielle dans un marché spécifique.', NULL, 4, 3.00, 0),
(109, 166, 1, '2024-12-19 14:00:00', 'Repérer, pour chaque activité de l’entreprise, le degré d’évolution des agrégats économiques correspondants', 'Analyse des données macroéconomiques (PIB, inflation, chômage) et leur influence sur les activités de l’entreprise.', 'Les étudiants peinent à relier les concepts macroéconomiques à la gestion d’entreprise.', 'Proposer une recherche guidée sur les données économiques marocaines récentes.', NULL, 4, 3.00, 0),
(110, 167, 1, '2024-12-26 14:00:00', 'Identifier nommément tous les types d’acteurs de financement en relation avec l’activité de l’entreprise', 'Présentation des institutions financières et des outils de financement (banques, leasing, capital-risque).', 'Les types d’acteurs financiers sont souvent mal différenciés.', 'Fournir des études de cas d’entreprises utilisant différents modes de financement.', NULL, 4, 3.00, 0),
(111, 167, 1, '2025-01-02 14:00:00', 'Définir clairement le rôle de toutes les institutions monétaires et financières au Maroc. Analyser la mise en œuvre de l’administration et l’utilisation des systèmes d’organisation dans des PME/PMI', '-Étude des institutions comme Bank Al-Maghrib, AMMC, et leur impact sur la régulation et le financement\r\n-Étude des systèmes d’organisation modernes (ERP, CRM) et leur impact sur la productivité.', 'Peu de connaissance des institutions marocaines spécifiques.', 'Fournir une démonstration pratique', NULL, 4, 3.00, 0),
(112, 168, 1, '2025-01-09 14:00:00', 'Illustrer ces analyses par l ‘étude de nombreux exemples. Etudier très spécifiquement pour chaque fonction les moyens à mettre en œuvre et les processus de traitement.', '-Application des concepts vus en cours à des exemples concrets d’entreprises marocaines ou internationales.\r\n-Analyse des processus clés par fonction (finance, production, RH) pour optimiser les performances.', 'Objectif atteint totalement', 'Prévoir des exercices interconnectant plusieurs fonctions d’entreprise.', NULL, 4, 3.00, 0),
(113, 168, 1, '2025-01-16 14:00:00', 'En déduire la structure d’un système opérationnel. Etudier un système de pilotage interne', '-Construction d’un modèle opérationnel global en s’appuyant sur l’ensemble des processus clés identifiés.\r\n-Exploration des outils de contrôle de gestion, indicateurs clés (KPI), et tableaux de bord pour la prise de décision stratégique.', 'Les étudiants rencontrent des difficultés avec la conception des tableaux de bord.', 'Fin de l\'unité de formation', NULL, 4, 3.00, 0),
(114, 173, 1, '2024-10-02 14:00:00', 'Définir l’utilité des statistiques pour la prise de décision en gestion commerciale', 'Introduction aux concepts fondamentaux des statistiques et leur rôle dans l’aide à la décision pour les gestionnaires d’entreprises', 'Les étudiants montrent des difficultés à comprendre les applications pratiques des statistiques.', 'Fournir des études de cas concrets en gestion commerciale.', NULL, 4, 3.00, 0),
(115, 173, 1, '2024-10-09 14:00:00', 'Lire correctement les informations d’un tableau statistique', 'Enseigner comment extraire, analyser et interpréter les informations disponibles dans des tableaux de données.', 'La lecture des données multi-dimensionnelles est complexe pour certains.', 'Proposer des exercices progressifs avec des tableaux simples, puis plus complexes.', NULL, 4, 3.00, 0),
(116, 173, 1, '2024-10-16 14:00:00', 'Calculer les fréquences à partir des effectifs', 'Apprentissage des calculs de fréquences absolues et relatives, avec des exemples pratiques.', 'Les erreurs fréquentes concernent la distinction entre les fréquences cumulées et simples.', 'Prévoir des exercices étape par étape et des exemples d’application dans un contexte commercial.', NULL, 4, 3.00, 0),
(117, 174, 1, '2024-10-23 14:00:00', 'Interpréter correctement les évolutions d’une série de données statistiques', 'Analyse des tendances, cycles et fluctuations dans une série chronologique de données.', 'Les étudiants peinent à identifier les tendances linéaires ou saisonnières.', 'Prévoir des graphiques illustratifs pour faciliter l’analyse visuelle des données.', NULL, 4, 3.00, 0),
(118, 174, 1, '2024-10-30 14:00:00', 'Choisir, parmi les différentes méthodes d’observation statistiques de données, la méthode la plus adaptée au phénomène observé', 'Introduction aux méthodes d’observation (enquêtes, échantillonnage, recensements) et choix en fonction du phénomène étudié.', 'Confusion fréquente entre méthodes quantitatives et qualitatives.', 'Fournir des scénarios concrets pour justifier le choix des méthodes.', NULL, 4, 3.00, 0),
(119, 174, 1, '2024-11-09 08:00:00', 'Déterminer les résultats des observations. (Séance anticipée)', 'Compilation et interprétation des résultats obtenus après collecte de données, avec validation des hypothèses statistiques.', 'Les calculs manuels causent des erreurs dans les interprétations.', 'Introduire des outils statistiques comme Excel pour simplifier les calculs.', NULL, 4, 3.00, 0),
(120, 174, 1, '2024-11-13 14:00:00', 'Calculer les principaux indicateurs statistiques : mode, médiane, moyenne arithmétique et géométrique', 'Calculs et applications des indicateurs de tendance centrale pour des séries de données.', 'Difficultés à distinguer les cas où chaque indicateur est pertinent.', 'Fournir des exemples variés et des cas d’études réels.', NULL, 4, 3.00, 0),
(121, 174, 1, '2024-11-20 14:00:00', 'Calculer les caractéristiques de tendance centrale pour une série de données', 'Étude approfondie des indicateurs pour mesurer les caractéristiques centrales d’un ensemble de données.', 'Les erreurs se produisent souvent dans le regroupement des classes.', 'Proposer des exercices basés sur des données économiques ou commerciales.', NULL, 4, 3.00, 0),
(122, 174, 1, '2024-11-27 14:00:00', 'Dégager la signification des indicateurs calculés pour les besoins de l’analyse', 'Analyse et interprétation des résultats statistiques pour répondre aux objectifs de gestion ou de recherche.', 'Les interprétations restent parfois trop générales et peu spécifiques.', 'Prévoir des exercices où les étudiants doivent rédiger un rapport d’analyse.', NULL, 4, 3.00, 0),
(123, 174, 1, '2024-12-04 14:00:00', 'Structurer les données dans un tableau statistique en utilisant les différentes présentations possibles', 'Organisation des données brutes dans des tableaux clairs et lisibles avec une présentation adaptée au public cible.', 'La structuration est souvent mal alignée avec les normes de présentation.', 'Fournir un format standardisé à respecter dans tous les exercices.', NULL, 4, 3.00, 0),
(124, 174, 1, '2024-12-18 14:00:00', 'Traduire des tableaux statistiques en représentation graphique pour faciliter l’observation et l’analyse des phénomènes étudiés', 'Utilisation des outils de visualisation pour représenter les données graphiquement (histogrammes, courbes, diagrammes circulaires, etc.).', 'Difficultés dans le choix du type de graphique adapté.', 'Enseigner à choisir le graphique selon le type de données et le public visé.', NULL, 4, 3.00, 0),
(125, 175, 1, '2024-12-25 14:00:00', 'A partir d’une série chronologique dégager les liaisons entre deux phénomènes observés', 'Étude des corrélations et relations entre deux variables dans un contexte temporel.', 'Les étudiants confondent souvent corrélation et causalité.', 'Fournir des exemples pratiques avec des séries de données d’entreprise.', NULL, 4, 3.00, 0),
(126, 175, 1, '2025-01-08 14:00:00', 'A partir d’une série chronologique dégager les liaisons entre deux phénomènes observés', '-Continuer sur le même objectif\r\n-Projection', 'Bonne maîtrise de l\'objectif', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(127, 175, 1, '2025-01-15 14:00:00', 'Dans un environnement donné mesurer l’intensité de la liaison entre deux phénomènes', 'Calcul des coefficients de corrélation et interprétation des résultats pour comprendre les relations entre les variables.', 'Les concepts mathématiques liés à la corrélation sont mal compris.', 'Fournir une explication détaillée des formules et des exercices guidés avec des données réelles.', NULL, 4, 3.00, 0),
(128, 175, 1, '2025-01-22 14:00:00', 'Dans un environnement donné mesurer l’intensité de la liaison entre deux phénomènes', '-Continuer sur le même objectif\r\n', 'Objectif atteint totalement', 'Fin de l\'unité de formation', NULL, 4, 3.00, 0),
(129, 181, 1, '2024-10-04 14:00:00', 'Définir les sources communautaires, internes légales et conventionnelles', 'Présentation des différentes sources juridiques et leur importance dans la structuration du droit civil et commercial.', 'Les stagiaires ont montré des difficultés à distinguer les sources légales des conventionnelles.', 'Prévoir des exemples concrets pour illustrer chaque type de source.', NULL, 4, 3.00, 0),
(130, 181, 1, '2024-10-11 14:00:00', 'Identifier les usages commerciaux et pratiques au Maroc', 'Identification des pratiques commerciales spécifiques et des coutumes applicables dans le cadre juridique marocain.', 'Bonne compréhension des stagiaires, mais nécessitent plus d’exemples pratiques pour mieux contextualiser les usages commerciaux.', 'Préparer une étude de cas sur une transaction commerciale au Maroc.', NULL, 4, 3.00, 0),
(131, 181, 1, '2024-10-18 14:00:00', 'Analyser le caractère général de la jurisprudence', 'Analyse des rôles et des impacts des décisions judiciaires sur l’interprétation et l’application des lois.', 'Les stagiaires ont bien saisi l’importance de la jurisprudence, mais ont besoin de clarifications sur les jurisprudences célèbres.', 'Fournir des exemples de jurisprudence marocaine influente.', NULL, 4, 3.00, 0);
INSERT INTO `seances_pedagogiques` (`id`, `sequence_id`, `annee_scolaire_id`, `date_seance`, `objectif_pedagogique`, `description_activites`, `observations_formateur`, `dispositions_prochaine`, `heures_realisees`, `heures_officielles`, `heures_reelles`, `controle_continu`) VALUES
(132, 182, 1, '2024-10-25 14:00:00', 'Distinguer clairement acte et fait juridique en tant que source d’obligations', 'Explication des différences entre les actes volontaires et les faits juridiques dans la création des obligations légales.', 'Confusion persistante sur les notions d’acte volontaire et de fait juridique accidentel.', 'Prévoir des exercices pratiques pour différencier les deux concepts.', NULL, 4, 3.00, 0),
(133, 182, 1, '2024-11-01 14:00:00', 'Dégager le rôle de la preuve dans une situation donnée', 'Présentation des différents types de preuves et leur importance dans la résolution des litiges juridiques.', 'Les stagiaires ont assimilé les concepts mais nécessitent plus d’exemples pratiques.', 'Fournir des études de cas sur des situations nécessitant des preuves spécifiques.', NULL, 4, 3.00, 0),
(134, 182, 1, '2024-11-08 14:00:00', 'Repérer à qui incombe la charge de la preuve', 'Analyse des responsabilités liées à la charge de la preuve dans divers contextes juridiques.', 'Bonne compréhension générale, mais quelques stagiaires confondent les notions de preuve directe et indirecte.', 'Proposer des exercices interactifs pour assigner la charge de la preuve selon des cas concrets.', NULL, 4, 3.00, 0),
(135, 182, 1, '2024-11-15 14:00:00', 'Identifier le mode de preuve adapté', 'Étude des différents types de preuves (écrite, orale, matérielle) et de leur application selon le contexte juridique.', 'Difficultés à différencier les preuves acceptables dans le droit civil et le droit commercial.', 'Prévoir une comparaison directe des modes de preuves en droit civil et commercial.', NULL, 4, 3.00, 0),
(136, 182, 1, '2024-11-22 14:00:00', 'Mettre en évidence la particularité du droit de la preuve en matière commerciale', 'Explication des spécificités des preuves en droit commercial, notamment la liberté contractuelle et les usages commerciaux.', 'Les stagiaires ont montré un intérêt accru pour les preuves spécifiques aux transactions commerciales.', 'Fournir des exemples concrets de litiges commerciaux et les modes de preuves utilisés.', NULL, 4, 3.00, 0),
(137, 183, 1, '2024-11-29 14:00:00', 'Dégager les conséquences du principe de l’autonomie de la volonté', 'Analyse de l’impact de l’autonomie de la volonté sur la rédaction des contrats et l’établissement des obligations.', 'Compréhension correcte, mais des clarifications sont nécessaires sur les limites de ce principe.', 'Préparer des contrats fictifs pour démontrer l’autonomie et ses limites.', NULL, 4, 3.00, 0),
(138, 183, 1, '2024-12-02 14:00:00', 'Identifier des limites à la liberté contractuelle et leur raison d’être. Analyser le contrat comme source d’obligations.', '-Étude des restrictions légales imposées aux contrats pour protéger l’ordre public et les parties vulnérables.\r\n-Explication de la formation du contrat, des obligations des parties, et des implications juridiques.', 'Bonne compréhension des stagiaires, mais des erreurs dans l’identification des éléments essentiels du contrat.', 'Organiser une session de simulation pour rédiger et analyser des contrats simples.', NULL, 4, 3.00, 0),
(139, 183, 1, '2024-12-06 14:00:00', 'Analyser quelques contrats d’usage courant au Maroc pour repérer les obligations des parties. Définir le contrat comme force obligatoire et effet relatif (nullité, résolution et résiliation)', '-Étude de contrats communs tels que les contrats de vente, de bail, et de travail pour identifier les obligations respectives des parties.\r\n-Analyse des notions de nullité, résolution, et résiliation des contrats et leur impact sur les parties contractantes.', 'Les stagiaires manquent de pratique pour interpréter les termes contractuels.', 'Prévoir des exemples concrets pour expliquer chaque concept.', NULL, 4, 3.00, 0),
(140, 184, 1, '2024-12-16 14:00:00', 'Identifier la notion de responsabilité avec les fondements et leur évolution. Distinguer clairement les responsabilités mises en jeu (civile contractuelle et pénale).', '-Étude des bases de la responsabilité civile et pénale, et des évolutions récentes en droit marocain.\r\n-Explication des distinctions entre responsabilité civile contractuelle, délictuelle, et pénale dans divers scénarios.', 'Bonne compréhension théorique, mais des difficultés dans la mise en pratique.', 'Proposer des cas pratiques pour appliquer les notions de responsabilité dans divers contextes.', NULL, 4, 3.00, 0),
(141, 184, 1, '2024-12-20 14:00:00', 'Identifier les conditions de mise en œuvre en matière civile (dommage, lien de causalité). Distinguer nettement le droit commercial des autres branches de droit.', '-Analyse des concepts de dommage, lien de causalité, et faute dans les litiges civils.\r\n-Comparaison des caractéristiques spécifiques du droit commercial avec le droit civil et d’autres branches juridiques.', 'Les stagiaires maîtrisent les grandes distinctions mais manquent de pratique pour appliquer ces notions.', 'Proposer des cas pratiques pour établir les conditions de mise en œuvre en litige civil.', NULL, 4, 3.00, 0),
(142, 185, 1, '2024-12-23 14:00:00', 'Définir clairement le statut juridique du commerçant. Identifier nommément les différentes composantes du fonds de commerce et en définir la nature juridique.', '-Identification des conditions requises pour être considéré comme commerçant et des obligations légales qui en découlent.\r\n-Description des éléments constitutifs d’un fonds de commerce et leur qualification juridique.', 'Bonne compréhension générale des stagiaires, mais des questions sur les obligations fiscales spécifiques des commerçants.', 'Commencer un nouveau objectif pédogogique', NULL, 4, 3.00, 0),
(143, 185, 1, '2024-12-27 14:00:00', 'Identifier les actes commerciaux des actes civils. Distinguer clairement entre les différents types de sociétés.', 'Présentation des principaux types de sociétés (SARL, SA, SNC, etc.), avec leurs caractéristiques et conditions d’application.', 'Les stagiaires maîtrisent les notions générales mais nécessitent plus d\'exemples pratiques.', 'Prévoir des cas pratiques pour classer des entreprises selon leur type juridique.', NULL, 4, 3.00, 0),
(144, 185, 1, '2024-12-30 14:00:00', 'Définir les formalités juridiques pour la constitution des sociétés. Définir les dispositions légales relatives aux instruments juridiques de commerce.', '-Étude des étapes nécessaires à la création d’une société, incluant les documents requis et les démarches administratives.\r\n-Analyse des principaux instruments juridiques comme les contrats, lettres de change, et effets de commerce.', 'Les stagiaires ont montré une bonne compréhension, mais nécessitent plus de clarté sur les clauses spécifiques.', 'Fournir des exemples concrets pour chaque instrument juridique mentionné.', NULL, 4, 3.00, 0),
(145, 186, 1, '2025-01-03 14:00:00', 'Appliquer les droits communs des contrats commerciaux. Respecter des principes généraux de rédaction de contrats commerciaux.', '-Étude des droits et obligations des parties impliquées dans les contrats commerciaux.\r\n-Explication des éléments essentiels pour rédiger un contrat commercial conforme aux lois et pratiques en vigueur', 'Bonne assimilation des concepts,', 'Fournir des exemples concrets pour chaque instrument juridique mentionné.', NULL, 4, 3.00, 0),
(146, 186, 1, '2025-01-06 14:00:00', 'Traiter les transactions commerciales dans un contexte contractuel. Définir les différents moyens de paiement pratiqués par l’entreprise.', '-Analyse des étapes de négociation, exécution, et règlement des transactions commerciales.\r\n-Présentation des divers moyens de paiement, tels que chèques, virements, espèces, et leur réglementation.', 'Bonne compréhension théorique,', 'Entamer l\'objectif pédogogique suivant', NULL, 4, 3.00, 0),
(147, 187, 1, '2025-01-10 14:00:00', 'Remplir judicieusement une lettre de change. Respecter à la lettre les règles de paiements en espèces.', '-Formation à la création et au remplissage correct d’une lettre de change avec explication de ses implications légales.\r\n-Analyse des règles légales encadrant les paiements en espèces, incluant les plafonds et exigences de traçabilité.', 'Bonne assimilation de la théorie, mais des erreurs dans le remplissage', 'Fournir des exemples de lettres de change à compléter avec correction en groupe.', NULL, 4, 3.00, 0),
(148, 187, 1, '2025-01-13 14:00:00', 'Traiter et vérifier les chèques sous ses aspects réglementaires. Définir les règles de contentieux des chèques et effets de commerce.', '-Étude des étapes de traitement, vérification, et validation des chèques, incluant les responsabilités des parties.\r\n-Analyse des litiges courants liés aux chèques et effets de commerce, et les procédures légales pour les résoudre.', 'Les stagiaires maîtrisent les étapes, mais ont besoin de plus de pratique.', 'Fournir des études de cas sur des litiges et leurs solutions.', NULL, 4, 3.00, 0),
(149, 188, 1, '2025-01-17 14:00:00', 'Identifier les conséquences de l’existence d’une personnalité morale. Situer une société dans une catégorie du droit des sociétés.', '-Étude de l’impact juridique et fiscal de la personnalité morale pour les entreprises.\r\n-Analyse des critères permettant de classer les entreprises dans les différentes catégories légales.', 'Bonne compréhension des stagiaires', 'Fournir un tableau comparatif entre personnalité morale et physique pour les entreprises', NULL, 4, 3.00, 0),
(150, 188, 1, '2025-01-20 14:00:00', 'Apprécier la régularité de la constitution et du fonctionnement d’une société commerciale de type PME/PMI. Identifier le rôle et les particularités de l’assemblée générale ordinaire et extraordinaire.', '-Évaluation des documents statutaires et des démarches administratives pour garantir la conformité des entreprises.\r\n-Étude des responsabilités et procédures associées aux assemblées générales ordinaires et extraordinaires.', 'Les stagiaires comprennent les concepts mais manquent de pratique sur l\'analyse de documents réels.', 'Fournir des documents réels anonymisés pour analyse et correction en groupe', NULL, 4, 3.00, 0),
(151, 188, 1, '2025-01-24 14:00:00', 'Caractériser le rôle du commissaire aux comptes. Identifier les causes de dissolution d’une société.', '-Présentation des responsabilités et fonctions du commissaire aux comptes dans les entreprises commerciales.\r\n-Analyse des situations et décisions légales qui peuvent entraîner la dissolution d’une société.', 'Séance riche de question et de participation', 'Fin de l\'unité de la formation', NULL, 4, 2.00, 0),
(152, 221, 1, '2024-10-01 14:00:00', 'Définir la gestion des ressources humaines et préciser l’évolution de ses objectifs', 'Étude des concepts de GRH et de son rôle stratégique dans l’organisation.', 'Bonne compréhension générale, mais difficulté à relier théorie et pratique.', 'Utiliser des exemples concrets de mise en œuvre de la GRH dans différentes entreprises.', NULL, 6, 3.00, 0),
(153, 221, 1, '2024-10-02 16:00:00', 'Montrer les enjeux de la GRH pour l’entreprise et les salariés', 'Discussion sur l\'impact de la GRH sur la motivation, la productivité et la performance globale de l’entreprise.', 'Les stagiaires manquent d\'exemples pratiques pour visualiser les enjeux.', 'Proposer des études de cas d’entreprises ayant optimisé leur GRH pour de meilleurs résultats.', NULL, 6, 2.00, 0),
(154, 222, 1, '2024-10-08 14:00:00', 'Caractériser le contenu, les méthodes d’analyse et les enjeux de la gestion prévisionnelle de l’emploi', 'Exploration des outils de gestion prévisionnelle comme les fiches de postes et les analyses de besoins futurs en compétences.', 'Bonne compréhension des outils, mais manque de pratique sur leur application.', 'Organiser des ateliers pratiques pour réaliser des analyses prévisionnelles simples.', NULL, 6, 3.00, 0),
(155, 222, 1, '2024-10-09 16:00:00', 'Analyser l’évolution et les modalités de mise en œuvre de la GRH (recrutement, formation…)', 'Étudier les pratiques de recrutement, formation et gestion des talents en fonction des objectifs stratégiques.', 'Bonne compréhension générale', 'Fournir des études de cas', NULL, 6, 2.00, 0),
(156, 222, 1, '2024-10-15 14:00:00', 'Analyser le dialogue social dans l’entreprise', 'Identifier les mécanismes de communication entre employés et direction, y compris les rôles des syndicats et des représentants du personnel.', 'Les stagiaires comprennent les bases', 'Proposer des simulations de négociations sociales et des ateliers de résolution de conflits.', NULL, 6, 3.00, 0),
(157, 223, 1, '2024-10-16 16:00:00', 'Créer et mettre à jouir les dossiers du personnel', 'Apprendre à organiser et structurer les informations des employés dans des formats physiques et numériques, en respectant les obligations légales.', 'Bonne compréhension théorique, mais manque de maîtrise des outils numériques.', 'Fournir des modèles de dossiers numériques et des exercices de gestion documentaire', NULL, 6, 2.00, 0),
(158, 223, 1, '2024-10-22 14:00:00', 'Suivre les absences et les congés.', 'Utilisation d’outils de gestion pour enregistrer, analyser et planifier les absences et congés des employés.', 'Difficultés rencontrées dans le paramétrage des outils spécifiques.', 'Organiser une formation sur les logiciels RH les plus courants pour la gestion des absences et congés.', NULL, 6, 3.00, 0),
(159, 223, 1, '2024-10-23 16:00:00', 'Caractériser les postes de travail, les fonctions, les qualifications notamment dans le domaine administratif', 'Élaborer des fiches de poste détaillant les missions, responsabilités et qualifications nécessaires pour chaque poste.', 'Les stagiaires maîtrisent les bases mais manquent de précision dans la description des postes.', 'Fournir un guide de rédaction et des exemples concrets de fiches de poste.', NULL, 6, 2.00, 0),
