(161, 224, 1, '2024-10-30 16:00:00', 'Participer à la définition des besoins en personnel', 'Identifier les besoins en recrutement à court et moyen terme en fonction des évolutions organisationnelles.', 'Les stagiaires comprennent les concepts mais manquent d’expérience pratique.', 'Proposer des exercices de planification des ressources humaines', NULL, 6, 2.00, 0),
(162, 224, 1, '2024-11-05 14:00:00', 'Concevoir une annonce et sélectionner les candidatures', 'Rédiger des annonces claires et attractives, et appliquer des critères objectifs pour sélectionner les candidatures.', 'Les stagiaires ont des difficultés à adapter les annonces à des postes spécifiques.', 'Fournir des exemples d’annonces et organiser des simulations d’entretiens de recrutement.', NULL, 6, 3.00, 0),
