(164, 224, 1, '2024-11-13 16:00:00', 'Etablir le contrat de travail', 'Rédiger des contrats conformes aux normes juridiques, adaptés aux spécificités des postes et au contexte légal.', 'Bonne maîtrise des éléments de base', 'Fournir des modèles de contrats avec des explications détaillées sur chaque clause', NULL, 6, 2.00, 0),
(165, 224, 1, '2024-11-19 14:00:00', 'Identifier les besoins en formation', 'Diagnostiquer les besoins en développement des compétences pour améliorer la performance des employés et de l’organisation.', 'Bonne compréhension des concepts', 'Fournir des outils d’analyse pour établir des priorités dans les besoins en formation', NULL, 6, 3.00, 0),
(166, 224, 1, '2024-11-20 16:00:00', 'Participer à la définition et au suivi administratif et budgétaire des actions de formation et Apprécier leur efficacité', 'Suivre et évaluer les programmes de formation en fonction de leur coût et de leur impact sur les compétences des employés.', 'Bonne compréhension générale', 'Fournir des matrices d’évaluation des formations et des indicateurs de performance.', NULL, 6, 2.00, 0),
(167, 224, 1, '2024-11-26 14:00:00', 'Assurer le suivi et le tutorat des stagiaires dans l’entreprise', 'Mettre en œuvre un programme de tutorat pour intégrer efficacement les stagiaires dans l’organisation.', 'Bonne maîtrise des concepts', 'Proposer des modèles de fiches de suivi pour stagiaires et des outils d’évaluation.', NULL, 6, 3.00, 0),
(168, 225, 1, '2024-11-27 16:00:00', 'Participer à la préparation et au suivi des actions de suivi du personnel en situation réelle', 'Planifier et superviser les tâches et projets confiés aux employés tout en assurant un suivi continu et des feedbacks réguliers.', 'Les stagiaires comprennent bien les étapes, mais manquent de compétences en communication efficace pour donner des feedbacks.', 'Proposer des ateliers de simulation pour pratiquer le suivi et la communication avec les équipes en situation réelle.', NULL, 6, 2.00, 0),
(169, 225, 1, '2024-12-03 14:00:00', 'Participer à la préparation et au suivi des actions de suivi du personnel en situation réelle', '-Continuer sur le même objectif\r\n-Travailler sur des ateliers de simulation pour pratiquer le suivi et la communication avec les équipes en situation réelle.', 'Objectif atteint totalement', 'Commencer un nouveau objectif', NULL, 6, 3.00, 0),
(170, 225, 1, '2024-12-04 16:00:00', 'Identifier les destinataires du tableau de bord', 'Reconnaître les responsables et parties prenantes clés qui utiliseront les données des tableaux pour la prise de décisions.', 'Bonne maîtrise de l’identification des parties prenantes, mais difficulté à adapter les indicateurs pour chaque groupe cible', 'Fournir des exemples réels de tableaux de bord différenciés selon les besoins des utilisateurs.', NULL, 6, 3.00, 0),
(171, 225, 1, '2024-12-10 14:00:00', 'Identifier les destinataires du tableau de bord', '-Suite de l\'objectif pédagogique\r\n-Travailler sur des exemples réels de tableaux de bord différenciés selon les besoins des utilisateurs.', 'Objectif atteint suite aux réponses des stagiaires', 'Entamer l\'objectif pédagogique suivant', NULL, 6, 3.00, 0),
(172, 225, 1, '2024-12-11 16:00:00', 'Identifier les critères pertinents de gestion du personnel en fonction des destinataires', 'Déterminer les indicateurs les plus pertinents en fonction des objectifs des utilisateurs du tableau de bord.', 'Bonne compréhension des critères généraux', 'Organiser des exercices pratiques', NULL, 6, 2.00, 0),
(173, 225, 1, '2024-12-17 14:00:00', 'Identifier les critères pertinents de gestion du personnel en fonction des destinataires', '-Continuer sur le même objectif\r\n-Exercices pratiques', 'Bonne maîtrise de l\'objectif', 'Passer à l\'objectif pédagogique suivant', NULL, 6, 3.00, 0),
(174, 225, 1, '2024-12-18 16:00:00', 'Collecter et vérifier les informations quantitatives, qualitatives et financières relatives au personnel', 'Appliquer des techniques de collecte rigoureuses et assurer la validité et la fiabilité des données obtenues.', 'Difficulté à identifier les sources fiables et à valider les informations collectées', 'Proposer des exercices pratiques avec des cas réels pour collecter et valider des données RH', NULL, 6, 2.00, 0),
(175, 225, 1, '2024-12-24 14:00:00', 'Collecter et vérifier les informations quantitatives, qualitatives et financières relatives au personnel', '-Continuer sur le même objectif\r\n-Travailler sur des exercices pratiques avec des cas réels pour collecter et valider des données RH', 'Objectif atteint totalement', 'Commencer un nouveau objectif', NULL, 6, 3.00, 0),
(176, 225, 1, '2024-12-25 16:00:00', 'Elaborer et alimenter le tableau de bord de suivi de l’activité du personnel', 'Créer des tableaux de bord dynamiques permettant de suivre la performance et les absences des employés de manière visuelle et synthétique.', 'Bonne compréhension théorique', 'Continuer sur le même objectif', NULL, 6, 2.00, 0),
(177, 225, 1, '2024-12-31 14:00:00', 'Elaborer et alimenter le tableau de bord de suivi de l’activité du personnel', '-Continuer sur le même objectif\r\n-Projection', 'Séance riche de question et de participation', 'Commencer un nouveau objectif', NULL, 6, 3.00, 0),
