(180, 225, 1, '2025-01-15 16:00:00', 'Formuler le commentaire destiné aux utilisateurs', 'Rédiger des synthèses claires et interprétatives des données présentées dans les tableaux de bord ou rapports.', 'Bonne capacité rédactionnelle,', 'Organiser des ateliers d’écriture pour s’adresser à différents types d’utilisateurs (RH, direction, employés).', NULL, 6, 2.00, 0),
(181, 225, 1, '2025-01-21 14:00:00', 'Formuler le commentaire destiné aux utilisateurs', '-Continuer sur le même objectif\r\n-Organiser des ateliers d’écriture pour s’adresser à différents types d’utilisateurs (RH, direction, employés).', 'Séance riche de participation', 'Fin de l\'unité de la formation', NULL, 6, 3.00, 0),
(182, 285, 1, '2024-10-04 08:00:00', 'Appliquer les principes fondamentaux de la comptabilité', 'Expliquer les bases de la comptabilité générale et son importance dans la gestion d’entreprise.', 'Les stagiaires assimilent bien les principes mais manquent d\'exemples pratiques.', 'Proposer des études de cas réels pour renforcer l’apprentissage.', NULL, 4, 3.00, 0),
(183, 285, 1, '2024-10-11 08:00:00', 'Rassembler et classer tous les éléments nécessaires à l’enregistrement comptable', 'Identifier les pièces comptables comme factures, reçus et justificatifs et les classer correctement', 'Bonne compréhension théorique, mais difficulté dans la manipulation des documents.', 'Organiser des ateliers avec des exemples de pièces comptables réelles.', NULL, 4, 3.00, 0),
(184, 285, 1, '2024-10-18 08:00:00', 'Enregistrer les opérations courantes et quotidiennes de l’entreprise, afin d’avoir l’image la plus fidèle de son activité économique', 'Saisir les transactions quotidiennes dans les journaux comptables en respectant les normes.', 'Les erreurs d’imputation sont fréquentes.', 'Fournir des exercices répétitifs sur l’enregistrement de transactions simples et complexes.', NULL, 4, 3.00, 0),
(185, 285, 1, '2024-10-25 08:00:00', 'Distinguer clairement entre les comptes du CPC de ceux du bilan', 'Expliquer la différence entre comptes de gestion (CPC) et comptes de situation (bilan).', 'Les stagiaires confondent parfois les deux types de comptes.', 'Fournir des tableaux comparatifs et des exercices de répartition des comptes.', NULL, 4, 3.00, 0),
