(190, 287, 1, '2024-11-29 08:00:00', 'Déterminer les résultats comptables et les représenter sous forme d’indicateurs', 'Calculer le résultat net, le taux de rentabilité et d’autres indicateurs financiers à partir des données comptables.', 'Les stagiaires maîtrisent bien les calculs,', 'Organiser des ateliers d’analyse des indicateurs et leur signification pour la gestion.', NULL, 4, 3.00, 0),
(191, 287, 1, '2024-12-06 08:00:00', 'Choisir et calculer, pour les besoins de l’analyse financière, les ratios de liquidité et les ratios d’autonomie financière reflétant au mieux la solvabilité de l’entreprise', 'Identifier les ratios clés pour évaluer la liquidité et l’autonomie financière et effectuer les calculs appropriés.', 'Les stagiaires comprennent bien les concepts', 'Fournir des exercices pratiques avec des données comptables simulées pour renforcer la compréhension', NULL, 4, 3.00, 0),
