(193, 287, 1, '2024-12-27 08:00:00', 'Déterminer le fond de roulement actuel de l’entreprise et le niveau souhaitable', 'Calculer le fond de roulement à partir des actifs et passifs circulants et comparer avec les besoins identifiés', 'Les stagiaires confondent souvent les données nécessaires pour le calcul.', 'Présenter des exemples ', NULL, 4, 3.00, 0),
(194, 287, 1, '2025-01-03 08:00:00', 'Déterminer le besoin en fond de roulement dégager par l’activité de l’entreprise. Suivre l’évolution de la trésorerie de l’entreprise pour une meilleure gestion financière', '-Identifier les postes impactant le besoin en fonds de roulement et effectuer les calculs nécessaires.\r\n-Analyser les flux de trésorerie pour anticiper les besoins et gérer efficacement la trésorerie.', 'Bonne compréhension des flux entrants et sortants,', 'Introduire des outils de simulation pour prévoir l’évolution de la trésorerie', NULL, 4, 3.00, 0),
(195, 288, 1, '2025-01-10 08:00:00', 'Calculer la Capacité d’autofinancement dégagée au cours de l’exercice. Déterminer clairement la marge commerciale de l’entreprise.', '-Identifier les charges non décaissées et les ajouter au résultat pour obtenir la capacité d’autofinancement.\r\n-Calculer la marge commerciale en déduisant le coût des ventes du chiffre d’affaires.', 'Bonne compréhension des formules', 'Fournir des exercices', NULL, 4, 3.00, 0),
(196, 288, 1, '2025-01-17 08:00:00', 'Analyser correctement la marge brute. Calculer les ratios de production par les comptes du bilan.', '-Calculer et interpréter la marge brute pour évaluer la performance opérationnelle de l’entreprise.\r\n-Identifier les ratios clés à partir du bilan pour évaluer la performance de la production.', 'Séance riche de question et de participation', 'Fin de l\'unité de la formation', NULL, 4, 3.00, 0),
(197, 320, 1, '2024-10-07 10:00:00', 'Identifier clairement l’intérêt de la mise en place d’un système de comptabilité analytique au sein de l’entreprise', 'Expliquer les avantages d’un système de comptabilité analytique pour la gestion des coûts et la prise de décision.', 'Bonne compréhension générale des concepts, mais besoin de plus d’exemples concrets', 'Fournir des études de cas pratiques sur l’impact de la comptabilité analytique sur la rentabilité.', NULL, 2, 2.00, 0),
(198, 320, 1, '2024-10-14 10:00:00', 'Identifier le processus de production de l’entreprise et les objectifs de gestion  recherchés par les responsables', 'Décomposer les étapes du processus de production et relier les objectifs de gestion à chaque étape.', 'Objectif atteint suite aux réponses des stagiaires', 'Utiliser des schémas pour clarifier les étapes du processus de production.', NULL, 2, 2.00, 0),
(199, 320, 1, '2024-10-21 10:00:00', 'Identifier nommément les centres d’analyse de l’entreprise', 'Présenter les différents centres d’analyse et leurs fonctions dans le calcul des coûts.', 'Bonne maîtrise des notions', 'Introduire un exercice d’identification des centres d’analyse à partir d’un organigramme d’entreprise.', NULL, 2, 2.00, 0),
(200, 320, 1, '2024-10-28 10:00:00', 'Organiser les flux d’informations entre les différents centres d’analyse pour les besoins de la comptabilité analytique', 'Démontrer comment les données circulent entre les différents centres d’analyse pour établir les coûts.', 'Bonne compréhension théorique, mais manque de pratique sur les flux d’information.', 'Proposer un atelier pratique où les stagiaires modélisent les flux d’information entre les centres.', NULL, 2, 2.00, 0),
(201, 321, 1, '2024-11-04 10:00:00', 'Identifier clairement les charges incorporables', 'Différencier les charges incorporables des charges non incorporables dans le processus de calcul des coûts.', 'Les stagiaires comprennent bien les bases', 'Fournir des exemples spécifiques de charges incorporables et non incorporables dans différents contextes', NULL, 2, 2.00, 0),
(202, 321, 1, '2024-11-11 10:00:00', 'Distinguer nettement entre charges directes et charges indirectes', 'Expliquer les différences entre charges directes et indirectes et leur impact sur les coûts.', 'Difficulté à classifier certaines charges complexes.', 'Fournir une grille simplifiée pour classer les charges directes et indirectes', NULL, 2, 2.00, 0),
(203, 321, 1, '2024-11-25 10:00:00', 'Identifier les charges indirectes et leurs clés de répartition entre centres d’analyse', 'Calculer les charges indirectes et définir des clés de répartition adaptées.', 'Bonne compréhension générale', 'Organiser des exercices de calcul avec des cas concrets.', NULL, 2, 2.00, 0),
(204, 321, 1, '2024-12-02 10:00:00', 'Tenir les comptes de stocks de manière permanente', 'Apprendre à enregistrer et suivre les mouvements de stock de manière continue.', 'Bonne compréhension des outils', 'Proposer des exercices pratiques ', NULL, 2, 2.00, 0),
(205, 322, 1, '2024-12-16 10:00:00', 'Traiter les coûts d’achat des matières premières ou des marchandises', 'Calculer précisément les coûts d’achat en intégrant les frais annexes (transport, taxes).', 'Les stagiaires maîtrisent le calcul', 'Introduire un tableau de synthèse pour faciliter l’intégration de tous les frais liés.', NULL, 2, 2.00, 0),
(206, 322, 1, '2024-12-23 10:00:00', 'Traiter les coûts de production par unité produite ou par commande', 'Calculer les coûts de production en fonction des unités produites ou des commandes passées.', 'Bonne maîtrise des formules', 'Fournir un exercice où les stagiaires doivent analyser un tableau de coûts de production réel.', NULL, 2, 2.00, 0),
(207, 322, 1, '2024-12-30 10:00:00', 'Traiter les coûts hors production', 'Identifier et calculer les charges liées aux activités hors production.', 'Difficulté à distinguer les charges spécifiques.', 'Fournir une liste détaillée des charges hors production courantes dans les entreprises.', NULL, 2, 2.00, 0),
(208, 322, 1, '2025-01-06 10:00:00', 'Traiter les coûts de revient par produit et par commande', 'Calculer les coûts de revient en additionnant les coûts de production et les frais annexes.', 'Bonne compréhension théorique, mais erreurs dans les calculs détaillés', 'Organiser un atelier pratique où les stagiaires établissent un coût de revient complet.', NULL, 2, 2.00, 0),
(209, 322, 1, '2025-01-13 10:00:00', 'Traiter les résultats analytiques par produit, par centre d’analyse et par commande', 'Analyser les résultats obtenus pour évaluer la rentabilité par produit, commande ou centre d’analyse.', 'Les stagiaires comprennent bien les concepts', 'Fournir des tableaux récapitulatifs avec des exercices d’interprétation des résultats.', NULL, 2, 2.00, 0),
(210, 323, 1, '2025-01-20 10:00:00', 'Distinguer clairement entre charges variables et charges fixes', 'Expliquer la différence entre charges variables et fixes et leur impact sur la gestion des coûts', 'Bonne compréhension générale,', 'Introduire des études de cas où les charges variables et fixes sont clairement définies.', NULL, 2, 2.00, 0),
(211, 323, 1, '2025-01-27 10:00:00', 'Déterminer de manière exacte la marge sur coûts variable. Calculer le seuil de rentabilité et le commenter.', '-Calculer la marge sur coûts variables et expliquer son utilité dans la prise de décision.\r\n-Calculer le seuil de rentabilité et analyser les implications pour la gestion de l’entreprise.', 'Les stagiaires comprennent bien les formules', 'Fin de l\'unité de la formation', NULL, 2, 2.00, 0),
(212, 8, 1, '2024-10-02 08:00:00', 'Analyse judicieuse de la structure de l\'entreprise', 'Étudier la structure organisationnelle de l’entreprise et ses implications sur les processus internes.', 'Bonne compréhension générale', 'Utiliser des schémas simplifiés pour expliquer les types de structures', NULL, 2, 2.00, 0),
(213, 8, 1, '2024-10-09 08:00:00', 'Interprétation juste des relations entre les sous systèmes de l’entreprise', 'Identifier les interactions et interdépendances entre les différents départements et sous-systèmes.', 'Relations bien identifiées', 'Proposer des études de cas réelles pour illustrer les interactions internes.', NULL, 2, 2.00, 0),
(214, 8, 1, '2024-10-16 08:00:00', 'Reconnaissance des différents types d’entreprise', 'Classifier les entreprises selon leurs tailles, secteurs d’activité et statuts juridiques.', 'Bonne classification, mais confusion dans certains statuts juridiques.', 'Préparer un tableau récapitulatif des types d’entreprise et leurs caractéristiques.', NULL, 2, 2.00, 0),
(215, 9, 1, '2024-10-23 08:00:00', 'Analyse correcte des interpolations entre le système entreprise et son contexte', 'Étudier comment l’entreprise interagit avec son environnement externe (clients, fournisseurs, marché, etc.).', 'Les étudiants saisissent les concepts, mais manquent d’exemples concrets.', 'Utiliser des études de marché ou des scénarios pour illustrer les interactions.', NULL, 2, 2.00, 0),
(216, 9, 1, '2024-10-30 08:00:00', 'Reconnaissance des différents flux d’entrée et de sortie', 'Identifier les flux d’informations, de ressources et de produits circulant dans l’entreprise.', 'Bonne identification', 'Introduire des exercices pratiques sur la cartographie des flux.', NULL, 2, 2.00, 0),
(217, 10, 1, '2024-11-13 08:00:00', 'Distinction juste des différentes fonctions de l’entreprise', 'Décrire et différencier les fonctions principales (RH, finance, production, marketing, etc.).', 'Bonne distinction globale', 'Fournir des descriptions simplifiées des fonctions principales', NULL, 2, 2.00, 0),
(218, 10, 1, '2024-11-20 08:00:00', 'Distinction juste des différentes fonctions de l’entreprise', '-Continuer sur le même objectif\r\n-Fournir des descriptions simplifiées des fonctions principales', 'Objectif atteint totalement', 'Commencer un nouveau objectif', NULL, 2, 2.00, 0),
(219, 10, 1, '2024-11-27 08:00:00', 'Mise en relation juste des fonctions de l’entreprise', 'Analyser les interconnexions entre les fonctions pour atteindre les objectifs de l’entreprise.', 'Objectif atteint partiellement', 'Organiser des discussions de groupe pour simuler des situations d’interdépendance', NULL, 2, 2.00, 0),
(220, 10, 1, '2024-12-04 08:00:00', 'Mise en relation juste des fonctions de l’entreprise', '-Suite de l\'objectif pédagogique\r\n-Organisation des discussions de groupe pour simuler des situations d’interdépendance', 'Séance riche de question et de participation', 'Commencer un nouveau objectif', NULL, 2, 2.00, 0),
(221, 10, 1, '2024-12-18 08:00:00', 'Identification du système d’information de l’entreprise', 'Étudier les outils et systèmes utilisés pour gérer les informations dans l’entreprise.', 'Bonne compréhension des concepts de base', 'Fournir des exemples', NULL, 2, 2.00, 0),
(222, 10, 1, '2024-12-25 08:00:00', 'Identification du système d’information de l’entreprise', '-Continuer sur le même objectif', 'Objectif atteint totalement', 'Passer à l\'objectif pédagogique suivant', NULL, 2, 2.00, 0),
(223, 11, 1, '2025-01-08 08:00:00', 'Distinction correcte entre les différentes structures', 'Comparer les structures fonctionnelles, matricielles et divisionnelles de l’entreprise.', 'Bonne distinction globale', 'Préparer une grille comparative pour chaque structure organisationnelle', NULL, 2, 2.00, 0),
(224, 11, 1, '2025-01-15 08:00:00', 'Distinction correcte entre les différentes structures', '-Continuer dur le même objectif', 'Objectif atteint totalement', 'Entamer l\'objectif pédagogique suivant', NULL, 2, 2.00, 0),
(225, 11, 1, '2025-01-22 08:00:00', 'Saisie correcte des motivations des choix entre les différentes structures', 'Étudier les facteurs influençant le choix de la structure organisationnelle.', 'Les étudiants comprennent les facteurs principaux', 'Fournir un exercice de simulation sur le choix de la structure', NULL, 2, 2.00, 0),
(226, 11, 1, '2025-01-29 08:00:00', 'Saisie correcte des motivations des choix entre les différentes structures', '-Suite de l\'objectif pédagogique\r\n-Fournir un exercice de simulation sur le choix de la structure', 'Séance riche de question et de participation', 'Fin de l\'unité de formation', NULL, 2, 2.00, 0),
(227, 49, 1, '2024-10-07 08:00:00', 'Collecte des données appropriées en ce qui concerne les besoins et l\'environnement de développement', 'Identifier et analyser les besoins fonctionnels et techniques avant de commencer la conception algorithmique.', 'Les étudiants doivent améliorer leur capacité à formuler des besoins techniques', 'Proposer des études de cas avec des exigences claires à analyser', NULL, 4, 3.00, 0),
(228, 49, 1, '2024-10-14 08:00:00', 'Collecte des données appropriées en ce qui concerne les besoins et l\'environnement de développement', '-Continuer sur le même objectif\r\n-Travailler sur des études de cas', 'Bonne maîtrise de l\'objectif', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(229, 49, 1, '2024-10-21 08:00:00', 'Précision des buts et des fonctions de l’algorithme', 'Déterminer clairement les objectifs que l’algorithme doit atteindre et les étapes à suivre pour y parvenir.', 'Bonne compréhension générale, mais manque de clarté dans certains objectifs.', 'Introduire des scénarios pratiques pour clarifier les attentes des algorithmes.', NULL, 4, 3.00, 0),
(230, 49, 1, '2024-10-28 08:00:00', 'Précision des buts et des fonctions de l’algorithme', '-Suite de l\'objectif pédagogique\r\n-Exercices pratiques', 'Objectif atteint totalement', 'Entamer l\'objectif pédagogique suivant', NULL, 4, 3.00, 0),
(231, 49, 1, '2024-11-04 08:00:00', 'Reconnaissance du type de données devant être traitées par le programme, des résultats et des traitements à effectuer', 'Classifier les données à manipuler et définir les résultats attendus en fonction des traitements requis.', 'Identification correcte des types simples, mais difficultés avec les types complexes.', 'Inclure des exercices de manipulation de types complexes ', NULL, 4, 3.00, 0),
(232, 49, 1, '2024-11-11 08:00:00', 'Reconnaissance du type de données devant être traitées par le programme, des résultats et des traitements à effectuer', '-Continuer sur le même objectif\r\n-Inclure des exercices de manipulation de types complexes ', 'Séance riche de participation', 'Entamer l\'objectif pédagogique suivant', NULL, 4, 3.00, 0),
(233, 50, 1, '2024-11-25 08:00:00', 'Développement d\'une solution algorithmique juste, précise et structurée', 'Concevoir une solution algorithmique efficace et bien organisée en respectant les principes de programmation structurée.', 'La structuration des algorithmes est satisfaisante, mais nécessite des améliorations pour la précision des solutions.', 'Utiliser des pseudo-codes pour guider la structuration des solutions.', NULL, 4, 3.00, 0),
(234, 50, 1, '2024-12-02 08:00:00', 'Développement d\'une solution algorithmique juste, précise et structurée', '-Continuer sur le même objectif\r\n-Utiliser des pseudo-codes pour guider la structuration des solutions.', 'Objectif atteint totalement', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(235, 50, 1, '2024-12-06 08:00:00', 'Représentation correcte de l\'ébauche du programme sous forme de pseudo-codes ou d’organigramme', 'Traduire les solutions algorithmique en pseudo-codes lisibles ou en organigrammes bien structurés.', 'Représentations visuelles souvent incomplètes ou imprécises.', 'Fournir des modèles standardisés pour les pseudo-codes et les organigrammes.', NULL, 4, 3.00, 0),
(236, 50, 1, '2024-12-16 08:00:00', 'Représentation correcte de l\'ébauche du programme sous forme de pseudo-codes ou d’organigramme', '-Continuer sur le même objectif\r\n-Fournir des modèles standardisés pour les pseudo-codes et les organigrammes.', 'Bonne compréhension de l\'objectif', 'Entamer l\'objectif pédagogique suivant', NULL, 4, 3.00, 0),
(237, 51, 1, '2024-12-20 08:00:00', 'Utilisation adéquate des procédures', 'Implémenter correctement des blocs de code réutilisables pour simplifier la structure du programme.', 'Bonne implémentation globale, mais les étudiants hésitent à modulariser leurs programmes.', 'Encourager l’utilisation de procédures pour des problèmes répétitifs.', NULL, 4, 3.00, 0),
(238, 51, 1, '2024-12-23 08:00:00', 'Utilisation adéquate des procédures', '-Continuer sur le même objectif', 'Objectif atteint totalement', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(239, 51, 1, '2024-12-27 08:00:00', 'Utilisation adéquate des fonctions', 'Exploiter des fonctions pour encapsuler des calculs ou traitements spécifiques et assurer la réutilisabilité.', 'Compréhension correcte des bases', 'Introduire des cas pratiques nécessitant la création de fonctions optimisées.', NULL, 4, 3.00, 0),
(240, 51, 1, '2024-12-30 08:00:00', 'Utilisation adéquate des fonctions', '-Suite de l\'objectif pédogogique\r\n-Introduire des cas pratiques nécessitant la création de fonctions optimisées.', 'Bonne maîtrise de l\'objectif', 'Passer à l\'objectif pédagogique suivant', NULL, 4, 3.00, 0),
(241, 51, 1, '2025-01-03 08:00:00', 'Exploitation correcte des procédures et des fonctions', 'Combiner les procédures et fonctions pour créer des programmes modulaires et bien structurés.', 'Bonne combinaison, mais des erreurs dans les appels de fonctions/procédures.', 'Expliquer les relations entre les procédures et les fonctions dans des scénarios pratiques.', NULL, 4, 3.00, 0),
(242, 51, 1, '2025-01-06 08:00:00', 'Exploitation correcte des procédures et des fonctions', '-Continuer sur le même objectif\r\n-Expliquer les relations entre les procédures et les fonctions dans des scénarios pratiques.', 'Objectif atteint suite aux réponses des stagiaires', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(243, 52, 1, '2025-01-10 08:00:00', 'Utilisation appropriée des tableaux', 'Manipuler des tableaux pour organiser et traiter des ensembles de données.', 'Bonne compréhension générale, mais des erreurs dans la manipulation d’indices.', 'Donner des exercices pratiques avec des tableaux multidimensionnels', NULL, 4, 3.00, 0),
(244, 52, 1, '2025-01-13 08:00:00', 'Utilisation appropriée des tableaux', '-Suite de l\'objectif pédagogique\r\n-Donner des exercices pratiques avec des tableaux multidimensionnels', 'Objectif atteint totalement', 'Passer à l\'objectif pédagogique suivant', NULL, 4, 3.00, 0),
(245, 52, 1, '2025-01-15 14:00:00', 'Utilisation appropriée des enregistrements (Séance anticipé)', 'Définir et manipuler des enregistrements pour gérer des données structurées.', 'Les étudiants rencontrent des difficultés à définir des enregistrements complexes.', 'Fournir des exemples concrets d’enregistrements liés à des applications réelles', NULL, 4, 3.00, 0),
(246, 52, 1, '2025-01-17 08:00:00', 'Utilisation appropriée des enregistrements', '-Continuer sur le même objectif\r\n-Fournir des exemples concrets d’enregistrements liés à des applications réelles', 'Objectif atteint totalement', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(247, 53, 1, '2025-01-18 08:00:00', 'Choix adéquat du type de fichiers à utiliser (Séance anticipé)', 'Identifier le type de fichier adapté en fonction des besoins de stockage et d’accès', 'Bonne compréhension générale, mais besoin de clarté sur les choix entre fichiers texte et binaires', 'Comparer les avantages et inconvénients des fichiers texte et binaires.', NULL, 4, 3.00, 0),
(248, 53, 1, '2025-01-20 08:00:00', 'Sauvegarde correcte des données', 'Implémenter des routines pour enregistrer des données dans des fichiers avec précision et fiabilité.', 'Bonne compréhension, mais des erreurs fréquentes lors de la sauvegarde dans des formats non appropriés.', 'Proposer des scénarios pour sauvegarder des données dans différents formats', NULL, 4, 3.00, 0),
(249, 53, 1, '2025-01-24 08:00:00', 'Restitution correcte des données', 'Lire et afficher correctement les données sauvegardées en utilisant les formats appropriés.', 'Les données sont souvent restituées correctement', 'Fin de l\'unité de formation', NULL, 4, 2.00, 0),
(250, 54, 1, '2024-10-01 08:00:00', 'Écriture correcte du code des instructions de base', 'Enseigner la syntaxe des instructions de base pour écrire des programmes structurés.', 'Les étudiants ont compris et appliqué les bases syntaxiques, quelques erreurs à corriger.', 'Prévoir des exercices pratiques pour renforcer la compréhension.', NULL, 4, 3.00, 0),
(251, 54, 1, '2024-10-04 08:00:00', 'Respect des règles syntaxiques', 'Expliquer les règles syntaxiques fondamentales des langages structurés.', 'Bonne assimilation des règles syntaxiques par les étudiants.', 'Introduire des exercices de vérification syntaxique automatique.', NULL, 4, 3.00, 0),
(252, 55, 1, '2024-10-08 08:00:00', 'Écriture correcte du code de manipulation des tableaux', 'Initier les étudiants à la manipulation correcte des tableaux à travers des exemples variés.', 'Manipulation correcte des tableaux, mais difficulté à gérer des dimensions complexes', 'Ajouter des exercices progressifs en complexité sur les tableaux multidimensionnels.', NULL, 4, 3.00, 0),
(253, 55, 1, '2024-10-11 08:00:00', 'Écriture correcte du code de manipulation des enregistrements ', 'Développer la compréhension et l’usage des structures d’enregistrements dans un programme.', 'Les étudiants ont saisi les concepts, mais ont besoin d’exercices supplémentaires.', 'Organiser une séance dédiée à la manipulation avancée des enregistrements', NULL, 4, 3.00, 0),
(254, 55, 1, '2024-10-15 08:00:00', 'Respect des règles syntaxiques', 'Renforcer l’application des règles syntaxiques apprises à travers des exemples pratiques.', 'Bonne application par la majorité des stagiaires', 'Continuer à inclure des vérifications systématiques dans les exercices pratiques.', NULL, 4, 3.00, 0),
(255, 56, 1, '2024-10-18 08:00:00', 'Utilisation correcte des fonctions et procédures', 'Introduire la création et l’utilisation des fonctions/procédures pour structurer les programmes.', 'Les étudiants réussissent à écrire des fonctions simples.', 'Intégrer des projets combinant plusieurs fonctions et procédures.', NULL, 4, 3.00, 0),
(256, 56, 1, '2024-10-22 08:00:00', 'Exploitation correcte des fonctions et procédures', 'Illustrer l’appel et l’utilisation des fonctions dans des scénarios réels.', 'Difficultés chez certains étudiants à combiner plusieurs fonctions dans un programme.', 'Prévoir une étude de cas en groupe.', NULL, 4, 3.00, 0),
(257, 56, 1, '2024-10-25 08:00:00', 'Respect des règles syntaxiques', 'Vérifier l\'application constante des règles syntaxiques apprises.', 'Les étudiants respectent les règles syntaxiques dans leurs travaux pratiques.', 'Introduire des outils d\'analyse statique pour automatiser les vérifications syntaxiques.', NULL, 4, 3.00, 0),
(258, 57, 1, '2024-10-29 08:00:00', 'Déclaration correcte des fichiers de données', 'Enseigner la déclaration et l’utilisation des fichiers dans un programme.', 'Déclarations correctes, mais besoin de clarifications sur les types de fichiers.', 'Ajouter des exemples concrets d’application des fichiers texte et binaire.', NULL, 4, 3.00, 0),
(259, 57, 1, '2024-11-01 08:00:00', 'Sauvegarde correcte des données', 'Former les étudiants à sauvegarder des données de manière sécurisée dans des fichiers.', 'Bonnes pratiques appliquées, mais quelques erreurs dans la gestion des noms de fichiers.', 'Ajouter une rubrique sur la gestion des exceptions lors de la sauvegarde.', NULL, 4, 3.00, 0),
(260, 57, 1, '2024-11-05 08:00:00', 'Restitution correcte des données', 'Initier les étudiants à lire et restituer des données sauvegardées dans des fichiers.', 'Les étudiants ont restitué les données correctement, mais des erreurs dans les formats.', 'Ajouter des exercices sur le formatage de la restitution.', NULL, 4, 3.00, 0);
INSERT INTO `seances_pedagogiques` (`id`, `sequence_id`, `annee_scolaire_id`, `date_seance`, `objectif_pedagogique`, `description_activites`, `observations_formateur`, `dispositions_prochaine`, `heures_realisees`, `heures_officielles`, `heures_reelles`, `controle_continu`) VALUES
(261, 58, 1, '2024-11-08 08:00:00', 'Application d\'une démarche méthodique de vérification', 'Enseigner une approche méthodique pour tester et vérifier les programmes.', 'Les étudiants comprennent l’importance des tests', 'Ajouter des scénarios pour vérifier les cas limites dans les programmes.', NULL, 4, 3.00, 0),
(262, 58, 1, '2024-11-12 08:00:00', 'Compilation du programme source', 'Présenter le processus de compilation et les messages d’erreur générés.', 'Bonne compréhension des étapes de compilation', 'Prévoir une séance sur les erreurs courantes de compilation et de linkage.', NULL, 4, 3.00, 0),
(263, 58, 1, '2024-11-15 08:00:00', 'Détection complète des erreurs de syntaxe, de logique et d\'exécution', 'Former les étudiants à analyser et corriger les erreurs dans les programmes.', 'Les erreurs syntaxiques sont corrigées, mais les erreurs logiques nécessitent plus de pratique.', 'Introduire un projet individuel pour détecter et corriger les erreurs dans un programme donné', NULL, 4, 3.00, 0),
(264, 58, 1, '2024-11-19 08:00:00', 'Correction juste des erreurs', 'Montrer comment identifier et corriger efficacement les erreurs dans un programme.', 'Les corrections sont souvent justes, mais les explications des corrections sont faibles.', 'Prévoir une auto-évaluation sur les corrections apportées', NULL, 4, 3.00, 0),
(265, 58, 1, '2024-11-26 08:00:00', 'Exécution du programme', 'Accompagner les étudiants dans l’exécution réussie de leurs programmes.', 'Les étudiants exécutent les programmes correctement', 'Intégrer des cas réels pour améliorer la robustesse des programmes face aux entrées utilisateur.', NULL, 4, 3.00, 0),
(266, 58, 1, '2024-12-03 08:00:00', 'Consignation précise des informations permettant de comprendre le programme', 'Apprendre à documenter correctement le programme avec des commentaires clairs', 'Bonne documentation, mais quelques étudiants n’utilisent pas de standard uniforme.', 'Proposer un modèle standardisé de documentation.', NULL, 4, 3.00, 0),
