(388, 255, 1, '2025-01-24 14:00:00', 'Identifier les lois liées à l’optique. (Séance anticipée)', '-Présentation théorique avec exercices pratiques sur logiciels.\r\n-Application des lois d’optique dans des projets graphiques', 'Séance riche de participation', 'Fin de l\'unité de la formation', NULL, 2, 2.00, 0),
(389, 295, 1, '2024-10-02 14:00:00', 'Utiliser de façon précise le vocabulaire multimédia', '-Introduction aux termes fondamentaux (bitmap, vectoriel, frame, etc.).\r\n-Étude des expressions techniques utilisées dans les projets multimédia.\r\n-Exercices pratiques pour identifier le vocabulaire dans des projets réels.', 'Bonne assimilation générale', 'Cours théorique accompagné d’un glossaire interactif', NULL, 4, 3.00, 0),
(390, 295, 1, '2024-10-09 14:00:00', 'Faire la différence entre l’analogique et la numérique', '-Comparaison des caractéristiques de l’analogique et du numérique.\r\n-Analyse des cas d’utilisation pour chaque technologie.\r\n-Démonstrations pratiques des conversions analogique-numérique.', 'Les stagiaires comprennent bien les différences, mais certains ont du mal avec les applications pratiques.', 'Présentation avec exemples visuels et exercices interactifs.', NULL, 4, 3.00, 0),
(391, 295, 1, '2024-10-16 14:00:00', 'Identifier les moyens de diffusion des projets multimédia', '-Exploration des plateformes de diffusion : web, applications, vidéos.\r\n-Analyse des avantages et limites de chaque moyen de diffusion.\r\n-Étude des formats adaptés pour chaque type de diffusion.', 'Bonne compréhension', 'Discussion de groupe suivie d’une analyse comparative.', NULL, 4, 3.00, 0);
INSERT INTO `seances_pedagogiques` (`id`, `sequence_id`, `annee_scolaire_id`, `date_seance`, `objectif_pedagogique`, `description_activites`, `observations_formateur`, `dispositions_prochaine`, `heures_realisees`, `heures_officielles`, `heures_reelles`, `controle_continu`) VALUES
(392, 295, 1, '2024-10-23 14:00:00', 'Identifier les différentes étapes de production multimédia', '-Étude des phases : conception, production, post-production.\r\n-Analyse des rôles impliqués dans chaque étape.\r\n-Création d’un plan simplifié pour un projet multimédia.', 'Les stagiaires ont bien intégré les étapes', 'Atelier interactif avec mise en situation réelle.', NULL, 4, 3.00, 0),
(393, 296, 1, '2024-10-30 14:00:00', 'Créer une image BITMAP et vectoriel', '-Réalisation d’une image bitmap avec un logiciel graphique.\r\n-Création d’une illustration vectorielle avec des outils appropriés.\r\n-Comparaison des résultats entre bitmap et vectoriel.', 'Bon travail général', 'Exercices pratiques sur logiciels (Photoshop, Illustrator).', NULL, 4, 3.00, 0),
(394, 296, 1, '2024-11-13 14:00:00', 'Manipuler un objet texte/image', '-Importation et modification de textes et images.\r\n-Superposition et alignement des éléments visuels.\r\n-Application d’effets visuels simples sur des objets.', 'Manipulation correcte, mais certains stagiaires doivent améliorer leur précision.', 'Atelier avec consignes claires et retours individualisés.', NULL, 4, 3.00, 0),
(395, 296, 1, '2024-11-20 14:00:00', 'Apprendre les différents types et techniques d’animation', '-Introduction aux animations classiques et numériques.\r\n-Réalisation d’une animation simple (stop-motion, interpolation).\r\n-Exploration des outils logiciels pour des animations avancées.', 'Les stagiaires comprennent bien les concepts', 'Activité pratique avec démonstration en temps réel.', NULL, 4, 3.00, 0),
(396, 296, 1, '2024-11-27 14:00:00', 'Utiliser des divers logiciels de production multimédia', '-Introduction aux logiciels comme Adobe Animate, After Effects, et Unity.\r\n-Manipulation de fonctions de base pour des projets multimédia.\r\n-Comparaison des fonctionnalités principales des logiciels.', 'Bonne maîtrise des outils,', 'Présentation guidée et exercices pratiques.', NULL, 4, 3.00, 0),
(397, 297, 1, '2024-12-04 14:00:00', 'Préparer un son et une vidéo', '-Découpe et montage audio avec un éditeur (Audacity).\r\n-Ajustement des paramètres vidéo avec un logiciel comme Premiere Pro.\r\n-Exportation dans des formats adaptés.', 'Les stagiaires maîtrisent bien les bases, mais doivent travailler sur les formats.', 'Atelier multimédia avec exercices dirigés.', NULL, 4, 3.00, 0),
(398, 297, 1, '2024-12-18 14:00:00', 'Identifier les différents formats de son et de vidéo', '-Présentation des formats audio : MP3, WAV, AAC.\r\n-Introduction aux formats vidéo : MP4, AVI, MOV.\r\n-Analyse des cas d’utilisation pour chaque format.', 'Bonne compréhension générale', 'Présentation théorique', NULL, 4, 3.00, 0),
(399, 297, 1, '2024-12-25 14:00:00', 'Préparer un clip pour Director', '-Importation et organisation d’éléments pour un clip.\r\n-Création d’une timeline et ajout d’animations.\r\n-Finalisation et préparation pour l’exportation.', 'Progrès satisfaisants', 'Travail individuel avec retour personnalisé.', NULL, 4, 3.00, 0),
(400, 297, 1, '2025-01-02 08:00:00', 'Exporter une animation en clip vidéo. Se conformer à une méthodologie de travail acquise. (Séance anticipée)', '-Paramétrage des options d’exportation.\r\n-Ajustement des formats pour une compatibilité maximale.\r\n-Application d’un workflow structuré pour un projet multimédia.\r\n-Documentation et suivi des tâches dans un tableau de bord.', 'Bonne organisation', 'Atelier pratique supervisé', NULL, 4, 3.00, 0),
(401, 298, 1, '2025-01-08 14:00:00', 'Comprendre l’importance des normes, nomenclatures et formats. Identifier les différences et les similarités entre projet WEB et projet Multimédia.', '-Étude des standards internationaux pour les multimédias.\r\n-Analyse des avantages d’une nomenclature cohérente.\r\n-Application des normes sur un projet simple.', 'Bonne compréhension des normes, mais quelques erreurs dans leur application', 'Atelier de correction collective sur des projets modèles.', NULL, 4, 3.00, 0),
(402, 298, 1, '2025-01-15 14:00:00', 'Programmer les scripts simples et complexes en utilisant les commandes lingo. Convertir un projet interactif en un projet WEB.', '-Création de scripts simples pour manipuler des objets interactifs avec Lingo.\r\n-Conception de fonctions complexes pour gérer les interactions utilisateur avancées.\r\n-Étude des exigences de compatibilité pour la conversion d’un projet interactif en format WEB.', 'Les stagiaires montrent une bonne maîtrise des concepts de base', 'Atelier avec simulation de conversion et validation .', NULL, 4, 3.00, 0),
(403, 298, 1, '2025-01-22 14:00:00', 'Concevoir des scripts à l’aide du langage Java. Utiliser et gérer les Xtras.', '-Introduction aux bases de la programmation avec Java (variables, boucles, fonctions).\r\n-Création de scripts interactifs pour animer des éléments multimédias.\r\n-Exploration des fonctionnalités des Xtras pour améliorer les projets multimédias.\r\n-Ajout, suppression et gestion des Xtras pour des besoins spécifiques.', 'Les stagiaires comprennent l’utilité des Xtras, mais certains ont du mal à les configurer correctement', 'Fin de l\'unité de la formation', NULL, 4, 3.00, 0),
(404, 310, 1, '2024-10-01 14:00:00', 'Se familiariser avec l’environnement 3D', '-Exploration des interfaces de logiciels 3D tels que Blender ou 3ds Max.\r\n-Identification des outils et des menus de base pour la création en 3D.\r\n-Découverte des raccourcis pour une navigation efficace dans l’espace 3D.', 'Les stagiaires prennent rapidement en main l’environnement, mais certains ont besoin de pratique supplémentaire pour la navigation 3D.', 'Démonstration en direct suivie d’une exploration individuelle sous supervision.', NULL, 4, 3.00, 0),
(405, 310, 1, '2024-10-08 14:00:00', 'Manipuler les outils de base destinés à la modification des objets', '-Utilisation des outils de transformation (déplacer, tourner, échelle).\r\n-Application des opérations de base : extrusion, découpe et duplication d’objets.\r\n-Manipulation des vertex, edges et faces pour la modification d’objets.', 'Bon niveau général', 'Atelier pratique avec exercices guidés et retours individualisés.', NULL, 4, 3.00, 0),
(406, 311, 1, '2024-10-15 14:00:00', 'Créer et modéliser de logos 3D', '-Conversion de logos 2D en objets 3D avec extrusion et biseautage.\r\n-Ajout de textures et de matériaux pour un rendu réaliste.\r\n-Placement et éclairage de la scène pour une meilleure visualisation du logo.', 'Bonne créativité dans la modélisation', 'Projet pratique avec exemples réels de logos à modéliser.', NULL, 4, 3.00, 0),
(407, 311, 1, '2024-10-22 14:00:00', 'Créer un environnement avec des éclairages', '-Placement des sources lumineuses pour simuler différents environnements.\r\n-Utilisation de l’éclairage HDRI pour des rendus photoréalistes.\r\n-Application des ombres et des effets d’éclairage avancés.', 'Les concepts d’éclairage HDRI sont bien compris,', 'Démonstration suivie d’un exercice de création d’une scène 3D complète avec éclairages.', NULL, 4, 3.00, 0),
(408, 311, 1, '2024-10-29 14:00:00', 'Exporter le projet', '-Sélection des formats d’exportation adaptés aux besoins multimédia (OBJ, FBX, etc.).\r\n-Configuration des paramètres de rendu pour optimiser la qualité du projet.\r\n-Validation du projet pour la compatibilité avec les logiciels tiers.', 'Exportation maîtrisée', 'Simulation d’un export avec différentes configurations', NULL, 4, 3.00, 0),
(409, 311, 1, '2024-11-05 14:00:00', 'Les effets visuels et le banc de montage', '-Ajout d’effets visuels simples (reflets, brillance, particules).\r\n-Manipulation des outils de montage pour synchroniser les séquences animées.', 'Bonne utilisation des effets visuels', 'Exercice pratique sur l’ajout d’effets visuels à une scène et montage d’une séquence courte', NULL, 4, 3.00, 0),
(410, 311, 1, '2024-11-12 14:00:00', 'Les effets visuels et le banc de montage', '-Exercice pratique sur l’ajout d’effets visuels à une scène et montage d’une séquence courte\r\n-Application d’effets avancés pour des rendus dynamiques.', 'Bonne maîtrise de l\'objectif', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(411, 312, 1, '2024-11-19 14:00:00', 'Étudier un story-board', '-Analyse des éléments graphiques et narratifs d’un story-board.\r\n-Identification des transitions et des plans nécessaires à la réalisation d’un projet.', 'Bonne compréhension des éléments d’un story-board, mais les transitions entre plans nécessitent une meilleure organisation.', 'Atelier collaboratif de conception d’un story-board à partir d’un scénario.', NULL, 4, 3.00, 0),
(412, 312, 1, '2024-11-26 14:00:00', 'Étudier un story-board', '-Atelier collaboratif de conception d’un story-board à partir d’un scénario.\r\n-Création d’un story-board simple pour un projet multimédia.', 'Bonne compréhension ', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(413, 312, 1, '2024-12-03 14:00:00', 'Découvrir les outils professionnels de modélisation animation éclairage destinés à la réalisation des projets multimédia', '-Présentation des fonctionnalités avancées des logiciels 3D (Blender, Maya, etc.).\r\n-Utilisation des outils d’animation pour créer des mouvements réalistes.', 'Les stagiaires apprennent rapidement les outils avancés, mais des exercices supplémentaires sont nécessaires pour l’animation fluide.', 'Formation guidée avec des exercices sur des projets réels pour renforcer les compétences.', NULL, 4, 3.00, 0),
(414, 312, 1, '2024-12-17 14:00:00', 'Découvrir les outils professionnels de modélisation animation éclairage destinés à la réalisation des projets multimédia', 'Simulation des effets de lumière dans des environnements complexes.', 'Bonne maîtrise de l\'objectif', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(415, 313, 1, '2024-12-24 14:00:00', 'Maîtriser l’animation multimédia', '-Création de séquences animées avec des objets et caméras.\r\n-Ajustement des courbes de mouvement pour des animations réalistes.', 'Animation bien réalisée', 'Exercices pratiques d’animation suivis de corrections en groupe.', NULL, 4, 3.00, 0),
(416, 313, 1, '2024-12-31 14:00:00', 'Maîtriser l’animation multimédia', '-Exercices pratiques d’animation suivis de corrections en groupe.\r\n-Intégration d’animations dans des projets interactifs.', 'Objectif atteint totalement', 'Entamer l\'objectif pédogogique suivant', NULL, 4, 3.00, 0),
(417, 313, 1, '2025-01-07 14:00:00', 'Ajouter des effets spéciaux à une séquence animée', '-Ajout de particules, flares et autres effets spéciaux aux animations.\r\n-Simulation d’effets environnementaux (pluie, vent, feu).', 'Les effets spéciaux sont bien intégrés', 'Atelier de création d’effets spéciaux, suivi d’une présentation des projets par les stagiaires.', NULL, 4, 3.00, 0),
(418, 313, 1, '2025-01-21 14:00:00', 'Ajouter des effets spéciaux à une séquence animée', '-Atelier de création d’effets spéciaux, suivi d’une présentation des projets par les stagiaires.\r\n- Rendu final avec intégration des effets spéciaux.', 'Séance riche de participation', 'Fin de l\'unité de formation.', NULL, 4, 3.00, 0),
(419, 316, 1, '2024-10-04 14:00:00', 'Appliquer les procédures d’utilisation d’un scanner', '-Introduction au fonctionnement des scanners et paramétrage des options.\r\n-Formation sur les types de formats de fichiers adaptés à la numérisation.\r\n-Identification des étapes pour une numérisation sans perte de qualité.', 'Les stagiaires maîtrisent les bases, mais nécessitent un peu de pratique pour optimiser les paramètres.', 'Atelier pratique avec des documents physiques variés pour scanner', NULL, 4, 3.00, 0),
(420, 316, 1, '2024-10-11 14:00:00', 'Déterminer la résolution optimale d’une image à scanner', '-Comprendre les concepts de résolution (DPI, PPI) et leur impact sur la qualité d\'image.\r\n-Ajuster les paramètres du scanner pour des usages spécifiques (impression ou web).\r\n-Utiliser des tests pratiques pour choisir la meilleure résolution.', 'Compréhension correcte', 'Exercices guidés avec scénarios spécifiques pour ajuster les DPI.', NULL, 4, 3.00, 0),
(421, 316, 1, '2024-10-18 14:00:00', 'Numériser une image avec le scanner', '-Pratique complète de la numérisation avec différents types de scanners.\r\n-Sauvegarde et exportation des fichiers numérisés dans les formats adaptés.\r\n-Optimisation de l\'image numérisée en fonction de son usage prévu.', 'Bonne manipulation des scanners', 'Projet individuel pour numériser et optimiser une image pour une campagne.', NULL, 4, 3.00, 0),
(422, 316, 1, '2024-10-25 14:00:00', 'Capturer des images digitales avec l’appareil photo numérique', '-Introduction aux paramètres de base des appareils photo (ISO, balance des blancs).\r\n-Capturer des images dans différentes conditions de lumière.\r\n-Transférer les photos sur ordinateur pour traitement.', 'Les stagiaires montrent un bon contrôle des réglages', 'Atelier en extérieur pour capturer des images dans différents environnements.', NULL, 4, 3.00, 0),
(423, 316, 1, '2024-11-01 14:00:00', 'Charger des images à partir d’une bibliothèque Cd-rom', '-Utilisation des bibliothèques d\'images standard pour trouver des ressources.\r\n-Extraction et organisation des images pour les intégrer à un projet.\r\n-Gestion des droits d’utilisation des images', 'Les stagiaires comprennent les bases, mais certains ont besoin d’aide pour organiser les images.', 'Simulation de projet nécessitant des images spécifiques à extraire d’une bibliothèque.', NULL, 4, 3.00, 0),
(424, 316, 1, '2024-11-08 14:00:00', 'Calibrer d’une manière simple une image', '-Introduction aux concepts de calibration pour ajuster les couleurs d’une image.\r\n-Utilisation des outils de calibration intégrés dans les logiciels d’édition (Photoshop, GIMP).\r\n-Vérification des résultats avant et après calibration.', 'Les stagiaires comprennent les bases, mais certains ont du mal à ajuster les paramètres correctement.', 'Activité pratique', NULL, 4, 3.00, 0),
(425, 317, 1, '2024-11-15 14:00:00', 'Définir une image et ses différents types', '-Exploration des types d’images (bitmap, vectorielle) et de leurs usages.\r\n-Étude des formats courants (JPEG, PNG, TIFF, SVG) et de leurs caractéristiques.\r\n-Analyse des avantages et inconvénients de chaque type selon les projets.', 'Les stagiaires identifient bien les types d’images,', 'Discussion en groupe sur des projets réels nécessitant des types d\'images différents.', NULL, 4, 3.00, 0),
(426, 317, 1, '2024-11-22 14:00:00', 'Paramétrer le logiciel de traitement d’image pour un traitement optimal', '-Configuration initiale des paramètres du logiciel pour les différents types de traitement.\r\n-Gestion des profils colorimétriques et des formats d\'image.\r\n-Optimisation des réglages pour améliorer la performance du logiciel.', 'Paramétrage réussi', 'Exercices d’optimisation.', NULL, 4, 3.00, 0),
(427, 317, 1, '2024-11-29 14:00:00', 'Apprendre les méthodes de sélection des pixels d’une image', '-Introduction aux outils de sélection (lasso, baguette magique, sélection rectangulaire) dans un logiciel de traitement d’image comme Photoshop ou GIMP.\r\n-Utilisation des réglages pour affiner les sélections (plage de couleurs, contours progressifs).', 'Les stagiaires manipulent correctement les outils', 'Atelier pratique avec images simples pour se familiariser avec les outils de sélection.', NULL, 4, 3.00, 0),
(428, 317, 1, '2024-12-06 14:00:00', 'Transformer, convertir et retoucher une image', '-Découverte des outils de retouche (clone, pinceau, sélection).\r\n-Conversion des formats d’image pour différents usages.\r\n-Application de retouches avancées pour améliorer la qualité visuelle.', 'Retouches bien réalisées, mais certains oublient les étapes de sauvegarde après conversion.', 'Projet pratique : retoucher une image et la préparer pour le web et l\'impression.', NULL, 4, 3.00, 0),
(429, 317, 1, '2024-12-20 14:00:00', 'Corriger les tons et les couleurs d’une image', '-Étude des couleurs et harmonies (teintes et saturation).\r\n-Démonstration : correction sélective de zones spécifiques d’une image.\r\n-Comparaison des résultats avec des palettes préréglées.', 'Bonne compréhension globale', 'Atelier individuel pour corriger plusieurs images avec des objectifs spécifiques', NULL, 4, 3.00, 0),
(430, 317, 1, '2024-12-27 14:00:00', 'Calculer la résolution et le ré échantillonnage', '-Explication des concepts de résolution (DPI, PPI).\r\n-Pratique : modification de la résolution pour différents supports (impression, écran).\r\n-Démonstration du rééchantillonnage pour réduire ou agrandir une image.', 'Bonne compréhension des concepts théoriques, mais certaines erreurs lors des ajustements pratiques.', 'Exercices guidés avec des formats standards pour écran et impression.', NULL, 4, 3.00, 0),
(431, 318, 1, '2025-01-03 14:00:00', 'Appliquer le maquillage, les filtres et les effets spéciaux. Préparer et optimiser les images destinées au Multimédia et au Web.', '-Introduction aux filtres et effets intégrés dans Photoshop ou GIMP.\r\n-Pratique : ajout d’effets spéciaux (flou, netteté, brillance).\r\n-Explication des formats d’image pour le Web (JPEG, PNG, GIF).\r\n-Optimisation des tailles d’images pour un chargement rapide.', 'Participation active', 'Travail pratique avec des comparaisons avant/après compression.', NULL, 4, 3.00, 0),
(432, 319, 1, '2025-01-10 14:00:00', 'Concevoir des animations simples à partir des images optimisées. Changer du codage des couleurs.', '-Introduction à l\'animation d\'images optimisées avec des logiciels comme Photoshop ou After Effects.\r\n-Démonstration : création de palettes personnalisées en HEX pour le Web.\r\n-Modification des couleurs en fonction des contraintes de supports imprimés ou numériques.', 'Les stagiaires progressent bien dans l’utilisation des palettes', 'Exercices pratiques avec des fichiers réels à convertir selon différents besoins.', NULL, 4, 3.00, 0),
(433, 319, 1, '2025-01-17 14:00:00', 'Utiliser les acteurs avec couche alpha et avec palette adaptative. Créer et faire des animations avec des palettes couleurs.', '-Introduction aux couches alpha : définition, utilisation et avantages pour les animations.\r\n-Introduction aux palettes de couleurs pour l’animation : sélection et gestion des palettes.\r\n-Création d’une animation simple utilisant une palette spécifique.', 'Résultats variés selon le niveau des stagiaires ; quelques-uns excellent dans les dégradés, tandis que d’autres nécessitent plus d’encadrement.', 'Fin de l\'unité de la formation.', NULL, 4, 3.00, 0),
(434, 32, 1, '2024-10-04 14:00:00', 'Description complète des opérations à effectuer', '-Identifier les étapes nécessaires pour exécuter une tâche donnée.\r\n-Présenter les opérations sous forme d’un schéma ou d’une liste ordonnée.\r\n-Appliquer chaque étape en suivant les consignes données.', 'Les étudiants respectent les étapes, mais certains ont du mal à structurer leur présentation.', 'Travail en binôme pour rédiger une fiche opérationnelle suivie d’une présentation orale.', NULL, 4, 3.00, 0),
(435, 33, 1, '2024-10-11 14:00:00', 'Reconnaissance de ses forces et de ses faiblesses quant à sa façon d\'agir et de communiquer avec des collègues, des supérieurs ou des clients', '-Réaliser un exercice d’auto-évaluation sur ses compétences relationnelles.\r\n-Identifier les points à améliorer et les forces à renforcer.\r\n-Discuter en groupe pour partager les observations et trouver des solutions.', 'Participation active avec des réflexions pertinentes', 'Travail individuel suivi d’un échange en groupe encadré.', NULL, 4, 3.00, 0),
(436, 33, 1, '2024-10-18 14:00:00', 'Exactitude des moyens à prendre pour améliorer ses relations interpersonnelles', '-Apprendre des techniques comme l’écoute active et la reformulation.\r\n-Appliquer ces techniques dans des mises en situation.', 'Les stagiaires intègrent bien les concepts', 'Mise en situation individuelle suivie d’une discussion de groupe', NULL, 4, 3.00, 0),
(437, 33, 1, '2024-10-25 14:00:00', 'Application rigoureuse des règles de politesse et de courtoisie', '-Étudier les principes fondamentaux de la politesse.\r\n-Appliquer ces principes dans différents contextes professionnels simulés.', 'Bonne compréhension', 'Exercices pratiques', NULL, 4, 3.00, 0),
(438, 33, 1, '2024-11-01 14:00:00', 'Adaptation de son approche selon les personnes et les situations', '-Observer et analyser les besoins spécifiques des interlocuteurs.\r\n-Ajuster son comportement et son langage en fonction de la situation.', 'Les étudiants montrent des capacités variées à s’adapter aux différentes situations.', 'Simulation de cas pratiques', NULL, 4, 3.00, 0),
(439, 33, 1, '2024-11-08 14:00:00', 'Utilisation appropriée des techniques de gestion des conflits interpersonnels', '-Étudier les techniques de gestion de conflits comme la médiation.\r\n-Appliquer ces techniques dans des simulations de situations conflictuelles.', 'Bonne implication', 'Jeux de rôle en binôme avec une analyse collective.', NULL, 4, 3.00, 0),
(440, 33, 1, '2024-11-15 14:00:00', 'Manifestation de comportements conformes à l\'éthique professionnelle', '-Appliquer les principes éthiques dans les simulations proposées.\r\n-Identifier les comportements non conformes et proposer des alternatives.', 'Les stagiaires montrent une compréhension adéquate mais doivent appliquer davantage les concepts dans des cas pratiques.', 'Étude de cas suivie d’une discussion guidée.', NULL, 4, 3.00, 0),
(441, 34, 1, '2024-11-22 14:00:00', 'Manifestation d\'une attitude d\'écoute et de réceptivité', '-Pratiquer des exercices d’écoute active (reformulation et validation).\r\n-Appliquer ces compétences dans des discussions en binôme ou en groupe.', 'Les stagiaires participent activement, mais certains ont des difficultés à reformuler efficacement.', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(442, 34, 1, '2024-11-29 14:00:00', 'Adaptation du niveau de langage selon l\'interlocuteur', '-Identifier les profils des interlocuteurs et leurs attentes.\r\n-Ajuster son langage (formel ou informel) selon la situation et le public cible.', 'Bonne compréhension globale', 'Jeux de rôle simulant des interactions variées', NULL, 4, 3.00, 0),
(443, 34, 1, '2024-12-06 14:00:00', 'Application correcte des techniques de communication verbale et non verbale', '-Apprendre les bases de la communication verbale et non verbale (gestes, posture, ton de voix).\r\n-Pratiquer ces techniques dans des dialogues simulés.', 'Les stagiaires comprennent bien les concepts', 'Exercices en binôme suivis d’une analyse en groupe.', NULL, 4, 3.00, 0),
(444, 34, 1, '2024-12-20 14:00:00', 'Utilisation appropriée des techniques de négociation et d\'argumentation', '-Etudier les principes de la négociation (écoute, compromis, argumentation).\r\n-Appliquer ces principes dans une simulation de conflit ou d\'accord commercial.', 'Bon investissement des stagiaires,', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
