(673, 302, 1, '2024-11-22 08:00:00', 'Réaliser les croquis et la maquette', 'Produire des esquisses préliminaires explorant différentes options créatives, développer un prototype représentatif de la version finale', 'Bonne compréhension', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(674, 302, 1, '2024-11-29 08:00:00', 'Créer des visuels', 'Concevoir des éléments graphiques originaux, respecter la charte graphique, ', 'Bonne compréhension', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
