(679, 303, 1, '2025-01-10 08:00:00', 'Créer une navigation a interactivité limpide', 'Concevoir une interface utilisateur intuitive, définir les parcours et interactions', 'Séance riche de participation', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
