(685, 154, 1, '2024-10-08 08:00:00', 'A travers des exemples d’application définir le principe de comptabilisation à partie double', 'Illustration avec des exemples simples de comptabilisation à partie double.', 'Bonne compréhension générale, mais difficultés à distinguer débit et crédit.', 'Séance pratique avec corrections collectives.', NULL, 4, 3.00, 0),
(686, 154, 1, '2024-10-14 08:00:00', 'A travers des exemples d’application définir le principe de comptabilisation à partie double', 'Exercice pratique : saisir des opérations comptables respectant la partie double.', 'Bonne compréhension générale,', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(687, 154, 1, '2024-10-15 08:00:00', 'Schématiser les flux économiques dans une entreprise en distinguant entre flux réels et flux monétaires', 'Les étudiants créent des diagrammes illustrant les flux d\'une entreprise.', 'Difficulté à visualiser les flux complexes dans certains cas.', 'Utilisation d\'outils visuels et numériques pour simplifier les flux.', NULL, 4, 3.00, 0),
