(689, 154, 1, '2024-10-22 08:00:00', 'Identifier pour une opération économique les comptes à mouvementer au niveau du plan comptable marocain', 'Analyse de cas pratiques pour identifier les comptes à mouvementer.', 'Bonne compréhension mais certains étudiants confondent catégories de comptes.', 'Révision des catégories avant exercices', NULL, 4, 3.00, 0);
INSERT INTO `seances_pedagogiques` (`id`, `sequence_id`, `annee_scolaire_id`, `date_seance`, `objectif_pedagogique`, `description_activites`, `observations_formateur`, `dispositions_prochaine`, `heures_realisees`, `heures_officielles`, `heures_reelles`, `controle_continu`) VALUES
