(711, 156, 1, '2025-01-21 08:00:00', 'Afin de respecter le principe de spécialisation des exercices, procéder aux régularisations des charges et des produits', 'Explication du principe de spécialisation des exercices et des régularisations nécessaires pour les charges et produits\r\n', 'Les étudiants comprennent bien la logique de régularisation\r\n', 'Apporter des cas pratiques pour renforcer la compréhension des régularisations des charges et produits\r\n', NULL, 4, 3.00, 0),
(712, 156, 1, '2025-02-03 08:00:00', 'Afin de respecter le principe de spécialisation des exercices, procéder aux régularisations des charges et des produits', 'Apporter des cas pratiques pour renforcer la compréhension des régularisations des charges et produits\r\n', 'Bonne compréhension', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
