(717, 158, 1, '2024-10-30 08:00:00', 'Identifier les politiques, les stratégies et les règles de management des différentes cultures', 'Présentation des pratiques de management adaptées aux contextes multiculturels', 'Questions pertinentes des étudiants sur les différences culturelles.', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(718, 158, 1, '2024-11-13 08:00:00', 'Définir le benchmarking et ses applications. Définir le reegineering et son rôle pour l’entreprise.', 'Expliquer les principes et étapes du benchmarking à l’aide d’exemples.\r\nAnalyse des processus de reengineering pour optimiser les opérations.', 'Bonne compréhension globale', 'Présenter un exemple', NULL, 4, 3.00, 0),
(719, 159, 1, '2024-11-20 08:00:00', 'Inventorier les sources d’informations existantes. Evaluer et sélectionner les sources d’information.', 'Identifier et différencier les sources internes et externes d’information.\r\n', 'Bonne participation,', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(720, 159, 1, '2024-11-27 08:00:00', 'Déterminer les conditions d’accès aux différentes informations. Utiliser les outils techniques de recherche documentaire usuels.', 'Identifier les protocoles et restrictions d’accès aux informations sensibles.', 'Bonne compréhension', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(721, 159, 1, '2024-12-04 08:00:00', 'Sélectionner les informations selon un ou plusieurs critères. Analyser les informations choisies et triées.', 'Appliquer des filtres pertinents pour extraire les données utiles.\r\nInterpréter les données sélectionnées pour produire des analyses ', 'Compréhension correcte', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(722, 159, 1, '2024-12-18 08:00:00', 'Relativiser les informations en fonction de leur contexte. Identifier les différents types de supports.', 'Adapter l’interprétation des informations au contexte spécifique.*\r\nÉtudier les supports d’information et leurs usages.', 'Bonne compréhension globale', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(723, 159, 1, '2024-12-25 08:00:00', 'Choisir le support adapté. Organiser l’information sur le support.', 'Identifier les critères pour choisir le support le plus approprié.\r\nAppliquer les principes de structuration des données sur divers supports.', 'Questions pertinente', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(724, 160, 1, '2025-01-08 08:00:00', 'Choisir et utiliser un ordre et un mode de classement pour tout type de document. Saisir et prendre des notes de manière rapide et concise et restituer les informations.', 'Appliquer les principes de structuration des données sur divers supports.\r\nÉtudier les méthodes de classement adaptées', 'Participation active', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
