(729, 208, 1, '2024-10-09 14:00:00', 'Identifier les différents coûts de stockage. Déterminer le niveau optimal des stocks.', 'Exploration des coûts directs et indirects liés à la gestion des stocks.\r\nApplication de méthodes mathématiques pour calculer le niveau optimal.', 'Bonne maîtrise des concepts', 'Déterminer la période inter-commande pour les marchandises et les matières premières', NULL, 2, 2.00, 0),
(730, 209, 1, '2024-10-16 14:00:00', 'Déterminer la période inter commande pour les marchandises et les matières premières. Analyser les consommations de matières .', 'Étude des méthodes pour fixer la période inter-commande.\r\nÉtude des historiques de consommation pour anticiper les besoins futurs.', 'Participation active', 'Commencer un nouveau objectif', NULL, 2, 2.00, 0),
(731, 209, 1, '2024-10-23 14:00:00', 'Suivre le mouvement des stocks en quantité en fonction des besoins de l’entreprise. Evaluer de manière permanente le stock de l’entreprise.', 'Présentation des méthodes de valorisation des stocks avec des exercices.', 'Bonne maîtrise des méthodes', 'Commencer un nouveau objectif', NULL, 2, 2.00, 0),
