(822, 137, 1, '2025-01-10 08:00:00', 'Codification judicieuse d’un service Web', 'Déploiement du service Web sur un serveur distant et test via Postman.', 'Bonne compréhension', 'Continuer sur le même objectif', NULL, 8, 3.00, 0),
(823, 137, 1, '2025-01-14 14:00:00', 'Codification judicieuse d’un service Web', 'Travail en binôme pour concevoir et tester un service Web', 'Bonne compréhension', 'Commencer un nouveau objectif', NULL, 8, 3.00, 0),
(824, 137, 1, '2025-01-17 08:00:00', 'Mise en œuvre correcte d’un service Web', 'Création d’une API permettant d’interagir avec une base de données en AJAX.', 'Les étudiants ont du mal à structurer leurs projets avec une approche API-first.', 'Continuer sur le même objectif', NULL, 8, 3.00, 0),
(825, 137, 1, '2025-01-21 14:00:00', 'Mise en œuvre correcte d’un service Web', 'Implémentation d’une API avec pagination pour optimiser la gestion des requêtes.', 'Bonne compréhension', 'Continuer sur le même objectif', NULL, 8, 3.00, 0),
(826, 137, 1, '2025-01-24 08:00:00', 'Mise en œuvre correcte d’un service Web', 'Sécurisation de l’API avec un système de jetons JWT (JSON Web Token).', 'Bonne compréhension', 'Continuer sur le même objectif', NULL, 8, 3.00, 0),
(827, 137, 1, '2025-02-04 14:00:00', 'Mise en œuvre correcte d’un service Web', 'Intégration de l’API dans une application front-end pour une démonstration complète.', 'Bonne compréhension', 'Continuer sur le même objectif', NULL, 8, 3.00, 0),
(828, 137, 1, '2025-02-07 08:00:00', 'Mise en œuvre correcte d’un service Web', 'Développement d’un projet final combinant back-end et front-end.', 'Bonne compréhension', 'Fin de l\'unité de formation', NULL, 8, 3.00, 0),
(829, 157, 1, '2025-02-04 08:00:00', 'Paramétrer le logiciel en fonction des caractéristiques de l’entreprise', 'Présentation des étapes de paramétrage du logiciel de comptabilité en fonction du type d’entreprise et de ses spécificités.', 'Les stagiaires assimilent bien la théorie, mais rencontrent des difficultés dans l’application pratique.', 'Exercices pratiques individuels.', NULL, 4, 3.00, 0),
(830, 157, 1, '2025-02-10 08:00:00', 'Paramétrer le logiciel en fonction des caractéristiques de l’entreprise', 'Configuration des paramètres de base (exercices comptables, plan comptable, TVA, mode de paiement)', 'Séance riche de participation', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(831, 157, 1, '2025-02-11 08:00:00', 'Saisir les différentes opérations de l’entreprise dans leurs journaux respectifs', 'Explication du principe de journalisation et des différentes opérations comptables (achats, ventes, trésorerie, opérations diverses).', 'La majorité des étudiants saisissent bien les opérations simples', 'Exercices dirigés sur des cas réels', NULL, 4, 3.00, 0),
(832, 157, 1, '2025-02-17 08:00:00', 'Saisir les différentes opérations de l’entreprise dans leurs journaux respectifs', 'Exercices dirigés sur des cas réels', 'La majorité des étudiants saisissent bien les opérations', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(833, 157, 1, '2025-02-18 08:00:00', 'Editer périodiquement des états de synthèse', 'Présentation des états financiers obligatoires (bilan, compte de résultat, tableaux de flux de trésorerie).', 'Bonne maîtrise de l’édition, mais difficulté dans l’interprétation des résultats', 'Explication des concepts suivie d’exercices pratiques', NULL, 4, 3.00, 0),
(834, 157, 1, '2025-03-03 08:00:00', 'Editer périodiquement des états de synthèse', 'Génération et interprétation des états financiers périodiques', 'Bonne interprétation des résultats.', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(835, 157, 1, '2025-03-10 08:00:00', 'Saisir les variables et les constantes de base de calcul des salaires (salaire brut, retenues à la source...)', 'Identification des différentes composantes du salaire et paramétrage des éléments variables sur le logiciel de paie.', 'Compréhension globale satisfaisante', 'Ateliers pratiques', NULL, 4, 3.00, 0),
(836, 157, 1, '2025-03-24 08:00:00', 'Saisir les variables et les constantes de base de calcul des salaires (salaire brut, retenues à la source...)', 'Saisie des données relatives aux employés et intégration des constantes (cotisations sociales, impôts).', 'Compréhension globale satisfaisante', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(837, 157, 1, '2025-03-31 08:00:00', 'Elaborer mensuellement des bulletins de paie pour le personnel', 'Explication des étapes de création des bulletins de paie et des obligations légales.', 'Compréhension globale satisfaisante', 'Simulation avec données réelles', NULL, 4, 3.00, 0),
(838, 161, 1, '2025-02-12 08:00:00', 'Examiner les causes. Proposer, tester et choisir les solutions.', 'Présentation des principales causes des dysfonctionnements organisationnels en entreprise. Définition des méthodes de résolution de problèmes et des critères de choix des solutions.', 'Bonne compréhension des théories', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(839, 161, 1, '2025-02-19 08:00:00', 'Mettre en œuvre les solutions retenues. Contrôler les résultats obtenus.', 'Présentation des étapes de mise en œuvre des solutions organisationnelles. Explication des techniques d’évaluation et de suivi des solutions mises en place.', 'Bonne compréhension', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(840, 162, 1, '2025-03-05 08:00:00', 'Déterminer les activités prioritaires selon l’importance et l’urgence. Prévoir le temps nécessaire pour l’exécution des activités.', 'Mise en application de la matrice sur des tâches spécifiques d’entreprise. Présentation des méthodes d’estimation du temps (PERT, Gantt).', 'Besoin d’améliorer l’application des outils de planification', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(841, 162, 1, '2025-03-12 08:00:00', 'Respecter les contraintes de calendrier. Vérifier que l’organisation mise en place permet d’atteindre les objectifs.', 'Définition des contraintes organisationnelles et des risques liés aux délais. Élaboration d’un tableau de suivi des objectifs d’une entreprise.', 'Compréhension satisfaisante', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(842, 162, 1, '2025-03-19 08:00:00', 'Concevoir et utiliser des listes de contrôle des agendas, des échéanciers, des plannings, des graphes. Définir les objectifs de la gestion des moyens.', 'Présentation des outils de gestion du temps et des plannings. Étude d’un plan de gestion des ressources d’une entreprise.', 'Maîtrise des outils', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(843, 171, 1, '2025-02-06 08:00:00', 'Utiliser la mise en page d’une feuille de calcul', 'Présentation des options de mise en page d’Excel et application des réglages pour structurer une feuille de calcul.', 'Bonne compréhension des outils', 'Exercices pratiques', NULL, 4, 3.00, 0),
(844, 171, 1, '2025-02-13 08:00:00', 'Utiliser les principales fonctions et les formules de calcul (mathématiques, financières, statistiques, etc.)', 'Introduction aux formules de base (somme, moyenne, minimum, maximum) et aux références absolues et relatives', 'Maîtrise des formules de base', 'Cas pratiques', NULL, 4, 3.00, 0),
(845, 171, 1, '2025-02-20 08:00:00', 'Utiliser les options d’impression d’une feuille de calcul', 'Explication des options d’impression et mise en pratique sur une feuille formatée.', 'Bonne assimilation des paramètres d’impression', 'Travail dirigé', NULL, 4, 3.00, 0),
(846, 171, 1, '2025-03-06 08:00:00', 'Utiliser les options d’impression d’une feuille de calcul', 'Réglage des zones d’impression et optimisation des impressions en format paysage et portrait.', 'Utilisation correcte', 'Nouveau objectif', NULL, 4, 3.00, 0),
(847, 171, 1, '2025-03-13 08:00:00', 'Transformer des tableaux de données en graphiques', 'Création et personnalisation de graphiques à partir de tableaux Excel.', 'Bonne création des graphiques', 'Continuer sur le même objectif', NULL, 4, 3.00, 0),
(848, 171, 1, '2025-03-27 08:00:00', 'Transformer des tableaux de données en graphiques', 'Comparaison entre différents types de graphiques pour représenter les mêmes données.', 'Bonne compréhension des types de graphiques', 'Nouveau objectif', NULL, 4, 3.00, 0),
(849, 191, 1, '2025-02-14 08:00:00', 'Prendre correctement des notes lors d’échanges ou exposés', 'Introduction aux techniques de prise de notes (abréviations, mots-clés, schématisation) avec mise en situation sur un extrait de conférence.', 'Bonne assimilation des méthodes', 'Nouveau objectif', NULL, 4, 3.00, 0),
(850, 191, 1, '2025-02-21 08:00:00', 'Caractériser de façon claire les différents signes de ponctuation', 'Présentation des principaux signes de ponctuation et leur rôle dans la phrase (ponctuation forte et faible).', 'Bonne connaissance des signes', 'Nouveau objectif', NULL, 4, 3.00, 0),
(851, 191, 1, '2025-03-07 08:00:00', 'Caractériser de façon exhaustive certaines expressions pouvant être utilisées en français', 'Étude des expressions courantes en français et de leur contexte d’utilisation (expressions idiomatiques, proverbes).', 'Bonne assimilation des expressions courantes', 'Fin de l\'unité de formation', NULL, 4, 3.00, 0),
(852, 176, 1, '2025-03-04 08:00:00', 'Calculer les intérêts simples générés par un placement sur une période donnée', 'Explication théorique de la formule des intérêts simples, avec application sur des cas pratiques de placements bancaires.', 'Bonne compréhension de la formule', 'Nouveau objectif', NULL, 4, 3.00, 0),
(853, 176, 1, '2025-03-11 08:00:00', 'Calculer les intérêts composés générés par les opérations financières avec la banque', ' Introduction à la formule des intérêts composés et distinction avec les intérêts simples. Exercice de comparaison entre intérêts simples et composés.', 'Bonne analyse des résultats', 'Nouveau objectif', NULL, 4, 3.00, 0),
(854, 176, 1, '2025-03-25 08:00:00', 'Pour les réductions financières accordées aux clients calculer le taux d’escompte relatif au délai de paiement', 'Explication du concept d’escompte et des avantages pour les entreprises. Étude de cas sur les effets de l’escompte pour un client.', 'Bonne compréhension de la logique de l’escompte', 'Nouveau objectif', NULL, 4, 3.00, 0);
INSERT INTO `seances_pedagogiques` (`id`, `sequence_id`, `annee_scolaire_id`, `date_seance`, `objectif_pedagogique`, `description_activites`, `observations_formateur`, `dispositions_prochaine`, `heures_realisees`, `heures_officielles`, `heures_reelles`, `controle_continu`) VALUES
(855, 178, 1, '2025-03-03 14:00:00', 'Identifier clairement les quatre étapes de la démarche marketing', 'Présentation des 4 étapes : analyse du marché, définition de la stratégie, mise en œuvre du plan marketing et contrôle des résultats. Étude de cas sur une entreprise fictive.', 'Bonne compréhension', 'Nouveau objectif', NULL, 2, 2.00, 0),
(856, 178, 1, '2025-03-10 14:00:00', 'Définir la notion de besoin, désir et demande', 'Exemples concrets de besoins fondamentaux, désirs créés par le marketing et demandes effectives sur le marché.', 'Bonne assimilation', 'Nouvau objectif', NULL, 2, 3.00, 0),
(857, 178, 1, '2025-03-24 14:00:00', 'Définir les actions du marketing (4P, 4P+FV, Mix, Systémie)', 'Explication des 4P (Produit, Prix, Place, Promotion) avec cas pratiques.', 'Participation active', 'Commencer un nouveau objectif', NULL, 2, 2.00, 0),
(858, 192, 1, '2025-03-04 14:00:00', 'Définir de manière exhaustive les différentes règles grammaticales et fonctionnelles de la langue anglaise', 'Révision des temps verbaux (présent, passé, futur) et de leur utilisation en contexte professionnel. Exercices pratiques de conjugaison.', 'Bonne assimilation des bases', 'Fiches récapitulatives', NULL, 8, 3.00, 0),
(859, 192, 1, '2025-03-07 08:00:00', 'Définir de manière exhaustive les différentes règles grammaticales et fonctionnelles de la langue anglaise', 'Application des règles de grammaire dans des phrases complexes et exercices de transformation de phrases.', 'Bonne assimilation des bases', 'Nouveau objectif', NULL, 8, 3.00, 0),
(860, 192, 1, '2025-03-11 14:00:00', 'Lire de manière compréhensible un texte en vue d’améliorer les outils de communication externe', 'Lecture d’un article professionnel et réponse à des questions de compréhension.', 'Bonne participation', 'Même objectif', NULL, 8, 3.00, 0),
(861, 192, 1, '2025-03-14 08:00:00', 'Lire de manière compréhensible un texte en vue d’améliorer les outils de communication externe', 'Lecture et résumé oral d’un texte en anglais. Discussion en classe.', 'Bonne participation', 'Nouveau objectif', NULL, 8, 3.00, 0),
(862, 192, 1, '2025-03-25 14:00:00', 'Caractériser de manière instructive les outils de dialogue, et de rédaction de lettres en langue anglaise', 'Présentation des différents types de correspondance professionnelle (email, lettre formelle, rapport). ', 'Bonne compréhension des structures', 'Même objectif', NULL, 8, 3.00, 0),
(863, 192, 1, '2025-03-28 08:00:00', 'Caractériser de manière instructive les outils de dialogue, et de rédaction de lettres en langue anglaise', 'rédaction et mise en situation d’un échange professionnel en anglais.', 'Bonne compréhension des structures', 'Nouveau objectif', NULL, 8, 3.00, 0),
(864, 199, 1, '2025-02-04 08:00:00', 'Evaluer l’activité normale d’un centre et Calculer une différence sur le niveau d’activité', 'Introduction aux notions d\'activité normale et effective d’un centre de coût. Exercices pratiques sur le calcul de la différence de niveau d’activité.', 'Bonne compréhension des principes de base', 'Support de cours avec exemples concrets', NULL, 4, 3.00, 0),
(865, 199, 1, '2025-02-05 08:00:00', 'Evaluer l’activité normale d’un centre et Calculer une différence sur le niveau d’activité', 'Étude de cas sur un centre de production : analyse des écarts et impact sur les coûts de production.', 'Participation active', 'Commencer un nouveau objectif', NULL, 4, 3.00, 0),
(866, 199, 1, '2025-02-11 08:00:00', 'Calculer le coût d’imputation rationnelle Apprécier l’utilité de ce calcul pour la gestion', 'Explication du concept d’imputation rationnelle et application à travers des exercices de répartition des charges indirectes.', 'Bonne compréhension des principes de base', 'Tableau récapitulatif des formules clés', NULL, 4, 3.00, 0),
(867, 199, 1, '2025-02-12 08:00:00', 'Calculer le coût d’imputation rationnelle Apprécier l’utilité de ce calcul pour la gestion', 'Simulation d’un calcul d’imputation rationnelle dans une entreprise fictive avec analyse des décisions de gestion.', 'Participation active', 'Fin de l\'unité de formation', NULL, 4, 3.00, 0),
(868, 204, 1, '2025-03-04 08:00:00', 'Caractériser clairement l’organisation du système de production de l’entreprise', 'Présentation des différents systèmes de production (production en série, à la commande, en continu). Étude de cas d’une entreprise industrielle.', 'Bonne assimilation des concepts', 'Nouveau objectif', NULL, 2, 2.00, 0),
(869, 204, 1, '2025-03-11 08:00:00', 'Identifier nommément les différentes étapes du processus de production', 'Explication du processus de production, du choix des matières premières à la fabrication et au contrôle qualité.', 'Compréhension correcte', 'Nouveau objectif', NULL, 2, 2.00, 0),
(870, 204, 1, '2025-03-25 08:00:00', 'Identifier et quantifier clairement les besoins de l’entreprise en matière de production', 'Initiation aux outils de prévision et de planification de la production .', 'Bonne utilisation des formules de prévision', 'Nouveau objectif', NULL, 2, 2.00, 0),
(871, 214, 1, '2025-03-05 14:00:00', 'Définir clairement la notion de centre de responsabilité', 'Introduction aux centres de responsabilité (centre de coût, centre de profit, centre d’investissement). Présentation des concepts et exemples concrets.', 'Bonne participation', 'Nouveau objectif', NULL, 2, 2.00, 0),
(872, 214, 1, '2025-03-12 14:00:00', 'Identifier les règles de constitution de centres de responsabilité', 'Explication des critères de constitution (autonomie, nature des coûts et revenus, structure hiérarchique).', 'Compréhension correcte', 'Nouveau objectif', NULL, 2, 2.00, 0),
(873, 214, 1, '2025-03-26 14:00:00', 'Identifier les limites de la responsabilité d’un centre de responsabilité', 'Analyse des risques et des limites des centres de responsabilité (problèmes de contrôle budgétaire, conflits internes, manque d’autonomie).', 'Participation active', 'Nouveau objectif', NULL, 2, 2.00, 0),
(874, 218, 1, '2025-03-03 08:00:00', 'Identifier les dispositions légales du droit des sociétés réglementant les aspects comptables', 'Présentation des principales lois et règlements encadrant la comptabilité des sociétés au Maroc (loi sur les sociétés anonymes, loi sur les SARL, normes comptables).', 'Bonne compréhension générale', 'Nouveau objectif', NULL, 2, 2.00, 0),
(875, 218, 1, '2025-03-10 08:00:00', 'Définir clairement les raisons de la spécificité de la comptabilité des sociétés', 'Explication des particularités comptables des sociétés (capital social, distribution des bénéfices, fusion, dissolution).', 'Compréhension correcte', 'Nouveau objectif', NULL, 2, 2.00, 0),
(876, 218, 1, '2025-03-24 08:00:00', 'Distinguer nettement entre les différents types de sociétés', 'Présentation des différents types de sociétés (SARL, SA, SNC, SCS…) avec leurs caractéristiques et implications comptables.', 'Bon niveau de participation', 'Nouveau objectif', NULL, 2, 2.00, 0),
(877, 231, 1, '2025-03-04 14:00:00', 'Définir la notion de droit. Distinguer clairement entre les différentes branches de droit.', 'Introduction générale au concept de droit et son rôle dans la société et le monde du travail.  Présentation des grandes branches du droit.', 'Bonne assimilation', 'Nouveau objectif', NULL, 4, 3.00, 0),
(878, 231, 1, '2025-03-10 14:00:00', 'Identifier nommément les différentes sources de droit. Définir clairement la notion d’obligation.', 'Explication des sources du droit (constitution, lois, jurisprudence, coutumes, doctrine) et leur hiérarchie. Présentation des obligations légales et contractuelles dans le cadre du droit du travail.', 'Bonne compréhension', 'Nouveau objectif', NULL, 4, 3.00, 0),
(879, 232, 1, '2025-03-24 14:00:00', 'Distinguer le droit social des autres branches de droit. Définir et spécifier le domaine du droit social.', 'Définition et caractéristiques du droit social en comparaison avec le droit civil et commercial. Présentation des champs d’application du droit social.', 'Participation active', 'Nouveau objectif', NULL, 4, 3.00, 0),
(880, 238, 1, '2025-02-14 08:00:00', 'Personnaliser la mise en page de la composition', 'Travail en binôme sur la création d’un modèle de document standardisé pour l’entreprise (lettres, rapports, CV, etc.)', 'Bonne créativité', 'Nouveau objectif', NULL, 4, 3.00, 0),
(881, 238, 1, '2025-02-21 08:00:00', 'Utiliser efficacement des jeux de couleurs pour l’ensemble des documents de l’entreprise', 'Présentation des principes de colorimétrie et choix des palettes de couleurs adaptées aux documents professionnels.', 'Bonne participation', 'Atelier pratique', NULL, 4, 3.00, 0),
(882, 238, 1, '2025-03-07 08:00:00', 'Utiliser efficacement des jeux de couleurs pour l’ensemble des documents de l’entreprise', 'Étude de cas d’entreprises utilisant des codes couleurs distincts et application sur des supports d’entreprise.', 'Bonne assimilation', 'Nouveau objectif', NULL, 4, 3.00, 0),
(883, 238, 1, '2025-03-14 08:00:00', 'Appliquer les différents types d’illustrations', 'Introduction aux types d’illustrations (icônes, images, graphiques) et leur usage professionnel.', 'Bonne compréhension', 'Même objectif', NULL, 4, 3.00, 0),
(884, 238, 1, '2025-03-28 08:00:00', 'Appliquer les différents types d’illustrations', 'Création d’un rapport ou d’une présentation PowerPoint', 'Bonne compréhension', 'Nouveau objectif', NULL, 4, 3.00, 0),
(885, 240, 1, '2025-03-03 14:00:00', 'Utiliser opportunément les principales expressions à usage commercial', 'Présentation et mise en pratique des expressions commerciales courantes (salutations, formules de politesse, phrases types pour les transactions).', 'Bonne assimilation', 'Même objectif', NULL, 8, 3.00, 0),
(886, 240, 1, '2025-03-05 08:00:00', 'Utiliser opportunément les principales expressions à usage commercial', 'Rédaction d’e-mails commerciaux en utilisant les expressions appropriées. Correction collective et feedback sur le ton et la structure du message.', 'Bonne assimilation', 'Exercices de mise en situation', NULL, 8, 3.00, 0),
(887, 240, 1, '2025-03-10 14:00:00', 'Utiliser opportunément les principales expressions à usage commercial', 'Simulation d’un échange commercial entre client et vendeur avec mise en application des expressions vues en cours.', 'Bonne assimilation', 'Nouveau objectif', NULL, 8, 3.00, 0),
(888, 240, 1, '2025-03-12 08:00:00', 'Dialoguer de manière compréhensible lors d’un échange professionnel en tenant compte du contexte linguistique et socio culturel', ' Étude des différences culturelles dans la communication professionnelle (style direct/indirect, ton formel/informel).', 'Bonne participation', 'Même objectif', NULL, 8, 3.00, 0),
(889, 240, 1, '2025-03-24 14:00:00', 'Dialoguer de manière compréhensible lors d’un échange professionnel en tenant compte du contexte linguistique et socio culturel', 'Simulation d’entretiens professionnels en français, avec adaptation du ton et du registre de langue selon l’interlocuteur ', 'Bonne participation', 'Même objectif', NULL, 8, 3.00, 0),
(890, 240, 1, '2025-03-26 08:00:00', 'Dialoguer de manière compréhensible lors d’un échange professionnel en tenant compte du contexte linguistique et socio culturel', 'Rédaction et mise en scène de dialogues professionnels en tenant compte du contexte (vente, négociation, réunion, service client).', 'Bonne structuration des dialogues', 'Nouveau objectif', NULL, 8, 3.00, 0),
(891, 243, 1, '2025-03-05 16:00:00', 'Utiliser opportunément les principales expressions à usage professionnel', 'Présentation et mise en pratique des expressions commerciales courantes (salutations, formules de politesse, phrases types pour les transactions).', 'Bonne assimilation', 'Nouveau objectif', NULL, 2, 3.00, 0),
(892, 243, 1, '2025-03-12 16:00:00', 'Dialoguer de manière compréhensible lors d’un échange professionnel en tenant compte du contexte linguistique et socio culturel', 'Etude des différences culturelles dans la communication professionnelle (style direct/indirect, ton formel/informel).', 'Bonne participation', 'Nouveau objectif', NULL, 2, 2.00, 0),
(893, 243, 1, '2025-03-26 16:00:00', 'Identifier nommément les règles de rédaction de la correspondance administrative', 'Présentation des structures des lettres administratives : Analyse des modèles de lettres (demandes, réclamations, convocations).', 'Bonne compréhension', 'Nouveau objectif', NULL, 2, 2.00, 0),
