(979, 60, 1, '2025-03-10 08:00:00', 'Création correcte des programmes en utilisant les instructions élémentaires et les instructions de contrôles', 'Présentation des instructions conditionnelles (if, else, switch).', 'Bonne assimilation des instructions conditionnelles', 'Exercices pratiques', NULL, 4, 3.00, 0),
