(981, 61, 1, '2025-03-24 08:00:00', 'Création et instanciation judicieuse des classes', 'Définition d’une classe avec attributs et méthodes.', 'Compréhension correcte', 'Atelier de programmation avec correction en groupe', NULL, 4, 3.00, 0),
