(986, 78, 1, '2025-03-04 14:00:00', 'Vérification appropriée du fonctionnement applications. Résolution efficace des problèmes d’installation.', 'Test de bon fonctionnement des logiciels installés après mise à jour et validation des dépendances.', 'Bonne méthode de vérification ', 'Nouveau objectif', NULL, 4, 3.00, 0),
(987, 79, 1, '2025-03-11 14:00:00', 'Choix des utilitaires appropriés. Mise en œuvre correcte des utilitaires permettant l’identification correcte des éléments qui réduisent la performance de l’installation.', 'Sélection et test des outils d’optimisation et de diagnostic matériel et logiciel.', 'Bonne utilisation des outils', 'Nouveau objectif', NULL, 4, 3.00, 0),
(988, 79, 1, '2025-03-25 14:00:00', 'Application correcte des procédures permettant d’améliorer la performance de l’installation. Respect des règles de sécurité.', 'Réglage des paramètres système pour optimiser les performances. Configuration des règles de sécurité : pare-feu, antivirus, gestion des accès.', 'Bonne mise en place des protections mais quelques oublis dans les mises à jour des règles de sécurité.', 'Nouveau objectif', NULL, 4, 3.00, 0),
